I18N.register("fr", {
  q: {
    "TPR1_01": ["Quelle est la prochaine étape ? ◇, ◇◇, ◇◇◇, ◇◇◇◇, ?", "Comptez les diamants à chaque étape.", ["◇◇◇◇◇", "◇◇◇", "◇◇◇◇", "◇◇"], "Un losange est ajouté à chaque étape : 1, 2, 3, 4, il y a donc 5 losanges."],
    "TPR1_02": ["Quelle est la prochaine étape ? A, B, C, D, E, ?", "Pense à l'ordre des lettres de l'alphabet.", ["F", "G", "D", "A"], "Ce sont des lettres consécutives de l’alphabet, donc la lettre suivante est F."],
    "TPR1_03": ["Quelle est la prochaine étape ? 1, 2, 3, 4, 5, ?", "Chaque nombre augmente du même pas.", ["6", "7", "5", "8"], "Chaque nombre augmente de 1, donc après 5 vient 6."],
    "TPR1_04": ["Quelle est la prochaine étape ? 2, 4, 6, 8, ?", "Regardez la différence entre les nombres consécutifs.", ["10", "12", "9", "11"], "Les étapes sont 2 par 2. Après 8, le prochain nombre pair est 10."],
    "TPR1_05": ["Quelle est la prochaine étape ? A, B, A, B, A, ?", "Observe le motif qui alterne.", ["B", "A", "C", "D"], "Le motif alterne A et B en continu, donc après A vient B."],
    "TPR1_06": ["Quelle est la prochaine étape ? □, □□, □□□, ?", "Comptez les carrés à chaque étape.", ["□□□□", "□□", "□□□□□", "□□□"], "Un carré est ajouté à chaque étape : 1, 2, 3, donc 4 carrés se suivent."],
    "TPR1_07": ["Quelle est la prochaine étape ? Z, Y, X, W, ?", "L'alphabet va à l'envers.", ["V", "U", "X", "T"], "Les lettres vont à rebours dans l’alphabet : Z, Y, X, W, V."],
    "TPR1_08": ["Quelle est la prochaine étape ? 10, 20, 30, 40, ?", "Chaque nombre augmente du même pas.", ["50", "45", "60", "55"], "Les étapes vont de 10 à 10. Après 40, le prochain terme est 50."],
    "TPR1_09": ["Quelle est la prochaine étape ? 3, 6, 9, 12, ?", "Chaque nombre augmente du même pas.", ["15", "14", "18", "13"], "Les pas sont de 3 par 3. Après 12, le prochain multiple de 3 est 15."],
    "TPR1_10": ["Complétez la grille : 1, 3, 5/7, 9, 11/13, 15, ?", "Classez les nombres impairs dans l’ordre, ligne par ligne.", ["17", "16", "19", "18"], "La grille répertorie les nombres impairs consécutifs : 1, 3, 5, 7, …, 15, 17."],
    "TPR1_11": ["Quelle est la prochaine étape ? ★, ★★, ★★★, ★★★★, ?", "Comptez les étoiles à chaque étape.", ["★★★★★", "★★★★", "★★★", "★★★★★★"], "Une étoile est ajoutée à chaque étape : 1, 2, 3, 4, donc 5 étoiles suivent."],
    "TPR1_12": ["Quelle est la prochaine étape ? 6, 12, 18, 24, ?", "Chaque terme est un multiple du même nombre – lequel ?", ["30", "28", "36", "32"], "Les pas vont de 6 à 6. Après 24, le prochain multiple de 6 est 30."],
    "TPR1_13": ["Quelle est la prochaine étape ? M, N, O, P, ?", "Ce sont des lettres consécutives de l'alphabet.", ["Q", "R", "N", "S"], "Les lettres continuent par ordre alphabétique : M, N, O, P, Q."],
    "TPR1_14": ["Quelle est la prochaine étape ? 1, 1, 1, 1, ?", "La valeur change-t-elle jamais ?", ["1", "2", "0", "3"], "Chaque terme vaut 1 — le modèle est constant, donc la valeur suivante est 1."],
    "TPR1_15": ["Quelle est la prochaine étape ? ♥, ♦, ♥, ♦, ♥, ?", "Deux symboles alternent.", ["♦", "♥", "♣", "♠"], "Le motif alterne coeur et diamant. Après le cœur vient le diamant."],
    "TPR1_16": ["Quelle est la prochaine étape ? 8, 16, 24, 32, ?", "Regardez la différence entre les nombres consécutifs.", ["40", "36", "48", "38"], "Les pas vont de 8 à 8. Après 32, le prochain multiple de 8 est 40."],
    "TPR1_17": ["Quelle est la prochaine étape ? ♠, ♠♠, ♠♠♠, ?", "Comptez les symboles du club à chaque étape.", ["♠♠♠♠", "♠♠", "♠♠♠", "♠♠♠♠♠"], "Un trèfle est ajouté à chaque étape : 1, 2, 3, il y a donc 4 trèfles."],
    "TPR1_18": ["Quelle est la prochaine étape ? 30, 27, 24, 21, ?", "Les nombres diminuent d'un pas fixe.", ["18", "20", "15", "19"], "Chaque nombre diminue de 3. Après 21, la valeur suivante est 18."],
    "TPR1_19": ["Quelle est la prochaine étape ? 7, 14, 21, 28, ?", "Chaque nombre est un multiple du même nombre.", ["35", "36", "32", "42"], "Les pas vont de 7 à 7. Après 28, le prochain multiple de 7 est 35."],
    "TPR1_20": ["Complétez la grille : 2, 4, 6/8, 10, 12/14, 16, ?", "Listez les nombres pairs ligne par ligne.", ["18", "20", "17", "19"], "La grille répertorie les nombres pairs consécutifs : 2, 4, 6, 8, …, 16, 18."],
    "TPR2_01": ["Quelle est la prochaine étape ? X, XY, XYX, XYXY, ?", "À chaque étape, un caractère supplémentaire est ajouté, en alternance entre X et Y.", ["XYXYX", "XYXYY", "YXYXY", "XXYX"], "Le motif s'agrandit par addition alternée : le 5ème terme comporte 5 caractères : XYXYX."],
    "TPR2_02": ["Grille : 3, 6, 9/5, 10, 15/8, 16, ?", "Regardez comment chaque ligne est liée au premier nombre de la ligne.", ["24", "20", "18", "32"], "Chaque ligne multiplie le premier nombre par 1, 2, 3. Ligne 3 : 8×1=8, 8×2=16, 8×3=24."],
    "TPR2_03": ["Quelle est la prochaine étape ? AA, BB, CC, DD, ?", "Chaque paire utilise la lettre suivante de l'alphabet.", ["EE", "FF", "DE", "AB"], "Chaque terme est une lettre consécutive doublée : A, B, C, D, E → EE."],
    "TPR2_04": ["Quelle est la prochaine étape ? 1, 3, 5, 7, 9, ?", "Ce sont des nombres impairs.", ["11", "10", "13", "12"], "La chaîne répertorie les nombres impairs consécutifs. Après 9, le prochain nombre impair est 11."],
    "TPR2_05": ["Quelle est la prochaine étape ? ○●, ○●○, ○●○●, ○●○●○, ?", "À chaque étape, une forme de plus est ajoutée en alternant ○ et ●.", ["○●○●○●", "○●○●○○", "●○●○●○", "○●○●●○"], "Le motif gagne une forme à chaque étape en alternant ○ et ●. Le terme suivant comporte six formes : ○●○●○●."],
    "TPR2_06": ["Quelle est la prochaine étape ? 2, 6, 10, 14, ?", "Trouvez la différence constante entre les termes.", ["18", "16", "20", "15"], "Chaque nombre augmente de 4. Après 14, la valeur suivante est 18."],
    "TPR2_07": ["Quelle est la prochaine étape ? AB, CD, EF, GH, ?", "Chaque paire utilise les deux lettres consécutives suivantes.", ["IJ", "JK", "HI", "KL"], "Les paires parcourent l'alphabet deux lettres à la fois : AB, CD, EF, GH, IJ."],
    "TPR2_08": ["Grille : 1, 3, 5/2, 4, 6/3, 5, ?", "Chaque ligne commence par un nombre plus élevé et ajoute la même étape.", ["7", "8", "6", "9"], "Chaque ligne répertorie trois nombres qui augmentent de 2. La ligne 3 commence à 3 : 3, 5, 7."],
    "TPR2_09": ["Quelle est la prochaine étape ? ○, ■, ○, ■, ○, ■, ?", "Deux formes se répètent dans le cycle.", ["○", "■", "△", "◇"], "Le motif alterne ○ et ■. Après ■ suit ○."],
    "TPR2_10": ["Quelle est la prochaine étape ? 20, 17, 14, 11, ?", "Les chiffres diminuent d'un montant fixe.", ["8", "9", "7", "10"], "Chaque nombre diminue de 3. Après 11, la valeur suivante est 8."],
    "TPR2_11": ["Quelle est la prochaine étape ? ABA, BCB, CDC, DED, ?", "Regardez comment les trois lettres de chaque groupe bougent.", ["EFE", "FGF", "DEF", "EEE"], "Chaque groupe suit le modèle : lettre, lettre suivante, même première lettre - décalée d'un pas dans chaque groupe. Après DED vient EFE."],
    "TPR2_12": ["Grille : 5, 10, 15/6, 12, 18/7, 14, ?", "Chaque ligne multiplie le premier nombre par 1, 2 et 3.", ["21", "20", "24", "28"], "Rangée 3 : 7×1=7, 7×2=14, 7×3=21."],
    "TPR2_13": ["Quelle est la prochaine étape ? 0, 2, 4, 6, 8, ?", "Ce sont des nombres pairs consécutifs commençant à 0.", ["10", "12", "9", "11"], "La chaîne répertorie les nombres pairs : 0, 2, 4, 6, 8, 10."],
    "TPR2_14": ["Quelle est la prochaine étape ? ○○, ■■, ○○, ■■, ?", "Les paires de formes alternent.", ["○○", "■■", "○■", "■○"], "Le motif alterne les paires : ○○, ■■, ○○, ■■, ○○."],
    "TPR2_15": ["Quelle est la prochaine étape ? 3, 7, 11, 15, 19, ?", "Trouvez la différence commune entre les termes.", ["23", "22", "21", "24"], "Chaque nombre augmente de 4. Après 19, la valeur suivante est 23."],
    "TPR2_16": ["Grille : 1, 2, 3/2, 4, 6/3, 6, ?", "Comparez chaque ligne avec la ligne au-dessus.", ["9", "8", "10", "12"], "La ligne n multiplie 1, 2, 3 par n. Rangée 3 : 3×1=3, 3×2=6, 3×3=9."],
    "TPR2_17": ["Quelle est la prochaine étape ? XY, WX, VW, UV, ?", "Chaque paire recule d’une lettre dans l’alphabet.", ["TU", "ST", "RS", "SU"], "Chaque paire descend d'une lettre : XY → WX → VW → UV → TU."],
    "TPR2_18": ["Quelle est la prochaine étape ? 40, 36, 32, 28, ?", "Les nombres diminuent d'une constante.", ["24", "25", "22", "20"], "Chaque nombre diminue de 4. Après 28, la valeur suivante est 24."],
    "TPR2_19": ["Quelle est la prochaine étape ? ○, ○○, ■, ■, ○, ?", "Une forme simple est suivie de son double, puis de la forme suivante.", ["○○", "■", "○", "■"], "Le cycle est : ○ simple, ○○ double, ■ simple, ■ double, puis répéter. Après ○ vient ○○."],
    "TPR2_20": ["Grille : 10, 20, 30/11, 22, 33/12, 24, ?", "Chaque ligne multiplie le premier nombre par 1, 2 et 3.", ["36", "34", "38", "48"], "Rangée 3 : 12×1=12, 12×2=24, 12×3=36."],
    "TPR3_01": ["Quelle est la prochaine étape ? 2, 3, 5, 8, 12, ?", "Regardez les différences entre les termes consécutifs : elles augmentent de 1.", ["17", "15", "16", "18"], "Les différences sont 1, 2, 3, 4, donc la différence suivante est 5 : 12 + 5 = 17."],
    "TPR3_02": ["Grille : 3, 5, 15/4, 6, 24/7, 3, ?", "Quel est le rapport entre les deux premières colonnes et la troisième ?", ["21", "10", "24", "30"], "Colonne 1 × colonne 2 = colonne 3. Ligne 3 : 7 × 3 = 21."],
    "TPR3_03": ["Quelle est la prochaine étape ? 49, 36, 25, 16, 9, ?", "Chaque terme est un carré parfait : de quels carrés s'agit-il ?", ["4", "1", "6", "3"], "La chaîne est 7², 6², 5², 4², 3², donc 2² = 4 suit."],
    "TPR3_04": ["Quelle est la prochaine étape ? 20, 18, 15, 11, 6, ?", "L'écart soustractif grandit de 1 à chaque pas (chute de plus en plus forte).", ["0", "1", "2", "−1"], "Les différences sont −2, −3, −4, −5, donc la suivante est −6 : 6 − 6 = 0."],
    "TPR3_05": ["Grille : 3, 9, 27/4, 16, 64/6, 36, ?", "Chaque ligne utilise les puissances du premier nombre.", ["216", "180", "108", "72"], "Le modèle de ligne est n¹, n², n³. Rangée 3 : 6, 36, 216."],
    "TPR3_06": ["Quelle est la prochaine étape ? 3, 5, 9, 15, 23, ?", "Calculez les différences – formez votre propre modèle.", ["33", "31", "35", "29"], "Les différences sont 2, 4, 6, 8, donc la suivante est 10 : 23 + 10 = 33."],
    "TPR3_07": ["Grille : 1, 5, 6/2, 8, 10/3, 11, ?", "Ajoutez les deux premières colonnes de chaque ligne.", ["14", "13", "15", "33"], "Colonne 1 + colonne 2 = colonne 3. Ligne 3 : 3 + 11 = 14."],
    "TPR3_08": ["Quelle est la prochaine étape ? 1, 6, 15, 28, 45, ?", "Regardez les différences, puis les différences de ces différences.", ["66", "60", "56", "72"], "Les différences sont 5, 9, 13, 17 (augmentation de 4). La différence suivante est 21 : 45 + 21 = 66."],
    "TPR3_09": ["Quelle est la prochaine étape ? 100, 95, 85, 70, 50, ?", "De combien diminue-t-il à chaque étape ? Ce montant est en augmentation.", ["25", "30", "20", "35"], "Les différences sont −5, −10, −15, −20, donc −25 suit : 50 − 25 = 25."],
    "TPR3_10": ["Grille : 3, 4, 12/5, 6, 30/7, 8, ?", "Quel est le rapport entre la colonne 3 et les colonnes 1 et 2 ?", ["56", "15", "48", "60"], "Colonne 1 × colonne 2 = colonne 3. Ligne 3 : 7 × 8 = 56."],
    "TPR3_11": ["Quelle est la prochaine étape ? 3, 8, 15, 24, 35, ?", "Essayez d'exprimer chaque terme sous la forme n² moins quelque chose.", ["48", "44", "50", "42"], "Chaque terme est n² − 1 : 2²−1=3, 3²−1=8, 4²−1=15, 5²−1=24, 6²−1=35, 7²−1=48."],
    "TPR3_12": ["Grille : 2, 10, 5/3, 18, 6/4, 28, ?", "Quel est le rapport entre la colonne 3 et les autres colonnes ?", ["7", "8", "12", "32"], "Colonne 2 ÷ colonne 1 = colonne 3. Ligne 3 : 28 ÷ 4 = 7."],
    "TPR3_13": ["Quelle est la prochaine étape ? 5, 6, 8, 11, 15, 20, ?", "Les différences entre les termes augmentent de 1 à chaque étape.", ["26", "25", "27", "24"], "Les différences sont 1, 2, 3, 4, 5, donc la suivante est 6 : 20 + 6 = 26."],
    "TPR3_14": ["Quelle est la prochaine étape ? 2, 5, 10, 17, 26, ?", "Essayez la formule n² + 1 pour les valeurs consécutives de n.", ["37", "35", "38", "36"], "Chaque terme est n² + 1 : 1²+1=2, 2²+1=5, 3²+1=10, 4²+1=17, 5²+1=26, 6²+1=37."],
    "TPR3_15": ["Grille : 2, 5, 7/3, 4, 7/8, 3, ?", "Ajoutez les deux premières colonnes de chaque ligne.", ["11", "24", "5", "10"], "Colonne 1 + colonne 2 = colonne 3. Ligne 3 : 8 + 3 = 11."],
    "TPR3_16": ["Grille : 6, 2, 3/15, 3, 5/24, 4, ?", "Divisez la colonne 1 par la colonne 2.", ["6", "8", "7", "28"], "Colonne 1 ÷ colonne 2 = colonne 3. Ligne 3 : 24 ÷ 4 = 6."],
    "TPR3_17": ["Quelle est la prochaine étape ? 2, 8, 32, 128, ?", "Chaque terme est multiplié par le même nombre.", ["512", "256", "384", "640"], "Chaque terme est multiplié par 4. Après 128, le terme suivant est 128 × 4 = 512."],
    "TPR3_18": ["Quelle est la prochaine étape ? 10, 12, 16, 22, 30, ?", "Voyez comment l'intervalle entre les termes change.", ["40", "38", "42", "36"], "Les différences sont 2, 4, 6, 8, donc la suivante est 10 : 30 + 10 = 40."],
    "TPR3_19": ["Quelle est la prochaine étape ? 4, 7, 12, 19, 28, ?", "Les différences entre les termes augmentent de 2 à chaque étape.", ["39", "37", "41", "35"], "Les différences sont 3, 5, 7, 9, donc la suivante est 11 : 28 + 11 = 39."],
    "TPR3_20": ["Grille : 4, 2, 8/9, 3, 27/16, 4, ?", "La colonne 1 est un carré parfait. Quelles sont les valeurs du cube ?", ["64", "48", "32", "20"], "Colonne 1 = n², colonne 2 = n, colonne 3 = n³. Rangée 3 : 4² = 16, 4, 4³ = 64."],
    "TPR4_01": ["Quelle est la prochaine étape ? 1, 16, 81, 256, ?", "Chaque terme est une quatrième puissance.", ["625", "512", "500", "1024"], "La chaîne est 1⁴, 2⁴, 3⁴, 4⁴, donc 5⁴ = 625 suit."],
    "TPR4_02": ["Grille : 5, 25, 125/6, 36, 216/7, 49, ?", "Chaque ligne affiche n, n², n³.", ["343", "294", "350", "336"], "Rangée 3 : 7¹ = 7, 7² = 49, 7³ = 343."],
    "TPR4_03": ["Quelle est la prochaine étape ? 2, 8, 26, 80, 242, ?", "Essayez d'exprimer chaque terme sous la forme d'une puissance de 3 moins 1.", ["728", "486", "720", "500"], "Chaque terme est 3ⁿ − 1 : 3¹−1=2, 3²−1=8, 3³−1=26, 3⁴−1=80, 3⁵−1=242, 3⁶−1=728."],
    "TPR4_04": ["Quelle est la prochaine étape ? 1, 4, 13, 40, 121, ?", "Chaque terme triple puis augmente de 1.", ["364", "242", "360", "400"], "Chaque terme = précédent × 3 + 1 : 1→4, 4→13, 13→40, 40→121, 121→364."],
    "TPR4_05": ["Quelle est la prochaine étape ? 2, 3, 5, 8, 13, ?", "Regardez les différences : cela suit un schéma familier.", ["21", "18", "20", "16"], "Les différences sont 1, 2, 3, 5, 8 — chaque différence est la somme des deux qui la précèdent. La différence suivante est 8, donc 13 + 8 = 21."],
    "TPR4_06": ["Quelle est la prochaine étape ? 1, 4, 10, 20, 35, ?", "Regardez les différences du second ordre : elles augmentent de 1.", ["56", "50", "48", "55"], "Différences du premier ordre : 3, 6, 10, 15. Différences du deuxième ordre : 3, 4, 5 → 6 suivant. Différence suivante du premier ordre : 21. Réponse : 35 + 21 = 56."],
    "TPR4_07": ["Quelle est la prochaine étape ? 1, 3, 2, 6, 4, 12, 8, ?", "Séparez la suite en termes aux positions impaires et aux positions paires.", ["24", "16", "10", "20"], "Positions impaires : 1, 2, 4, 8 (×2). Positions paires : 3, 6, 12, 24 (×2). Le prochain terme pair est 24."],
    "TPR4_08": ["Grille : 2, 3, 11/4, 5, 29/6, 7, ?", "Essayez (colonne1 + 1) × (colonne2 + 1) et ajustez.", ["55", "42", "48", "53"], "Colonne 3 = (colonne 1 + 1) × (colonne 2 + 1) − 1. Ligne 3 : 7 × 8 − 1 = 55."],
    "TPR4_09": ["Quelle est la prochaine étape ? 256, 128, 64, 32, 16, ?", "Chaque terme est divisé par deux.", ["8", "4", "12", "10"], "Chaque terme est divisible par 2. Après 16, le terme suivant est 16 ÷ 2 = 8."],
    "TPR4_10": ["Grille : 1, 2, 3, 6/2, 3, 5, 30/3, 4, 7, ?", "Quel est le rapport entre la dernière colonne et les trois premières ?", ["84", "14", "21", "72"], "Colonne 4 = colonne 1 × colonne 2 × colonne 3. Ligne 3 : 3 × 4 × 7 = 84."],
    "TPR4_11": ["Quelle est la prochaine étape ? 2, 6, 18, 54, ?", "Chaque terme est multiplié par le même nombre.", ["162", "108", "144", "216"], "Chaque terme est multiplié par 3. Après 54, le terme suivant est 54 × 3 = 162."],
    "TPR4_12": ["Quelle est la prochaine étape ? 1, 5, 14, 30, 55, ?", "Les différences entre les termes sont des carrés parfaits.", ["91", "80", "85", "90"], "Les différences sont 4, 9, 16, 25 (soit 2², 3², 4², 5²). La différence suivante est 6² = 36 : 55 + 36 = 91."],
    "TPR4_13": ["Quelle est la prochaine étape ? 1000, 500, 250, 125, ?", "Chaque terme est divisé par deux.", ["62,5", "60", "75", "100"], "Chaque terme est divisible par 2. Après 125, le terme suivant est 125 ÷ 2 = 62,5."],
    "TPR4_14": ["Grille : 10, 3, 7/20, 8, 12/30, 11, ?", "Comment les colonnes sont-elles liées arithmétiquement ?", ["19", "20", "21", "41"], "Colonne 1 − colonne 2 = colonne 3. Ligne 3 : 30 − 11 = 19."],
    "TPR4_15": ["Quelle est la prochaine étape ? 4, 5, 9, 14, 23, 37, ?", "Chaque terme est la somme des deux termes précédents.", ["60", "51", "56", "74"], "Comme pour Fibonacci : chaque terme = la somme des deux précédents. 23 + 37 = 60."],
    "TPR4_16": ["Grille : 2, 8, 3/3, 27, 8/4, 64, ?", "La colonne 2 est une puissance de la colonne 1. Quel modèle suit la colonne 3 ?", ["15", "16", "12", "20"], "Colonne 2 = colonne 1³. Colonne 3 = colonne 1² − 1 : 2²−1=3, 3²−1=8, 4²−1=15."],
    "TPR4_17": ["Quelle est la prochaine étape ? 1, 5, 21, 85, ?", "Essayez de multiplier chaque terme par 4 et d'ajouter 1.", ["341", "256", "340", "345"], "Chaque terme = précédent × 4 + 1 : 1→5, 5→21, 21→85, 85→341."],
    "TPR4_18": ["Quelle est la prochaine étape ? 1, 2, 5, 12, 29, ?", "Chaque terme utilise les deux précédents avec un multiplicateur.", ["70", "58", "65", "72"], "Règle : a(n) = 2×a(n−1) + a(n−2). Vérifiez : 2×2+1=5, 2×5+2=12, 2×12+5=29, 2×29+12=70."],
    "TPR4_19": ["Grille : 3, 2, 11/4, 3, 19/5, 4, ?", "Essayez de mettre au carré la colonne 1 et la colonne 2.", ["29", "20", "25", "30"], "Colonne 3 = colonne 1² + colonne 2. Ligne 3 : 5² + 4 = 25 + 4 = 29."],
    "TPR4_20": ["Grille : 4, 3, 13/5, 2, 23/6, 1, ?", "Essayez la colonne 1 au carré moins la colonne 2.", ["35", "30", "36", "42"], "Colonne 3 = colonne 1² − colonne 2. Ligne 3 : 6² − 1 = 36 − 1 = 35."],
    "TPR5_01": ["Quel nombre suit dans la suite des nombres premiers : 23, 29, 31, 37, 41, ?", "Listez les nombres premiers après 41.", ["43", "42", "45", "47"], "La chaîne répertorie les nombres premiers consécutifs. Après 41, le prochain nombre premier est 43."],
    "TPR5_02": ["Quelle est la prochaine étape ? 2, 1, 3, 4, 7, 11, 18, ?", "Chaque terme est la somme des deux termes précédents.", ["29", "25", "27", "36"], "Série de Lucas : chaque terme = la somme des deux qui le précèdent. 11 + 18 = 29."],
    "TPR5_03": ["Grille : 2, 8, 32/3, 27, 243/5, 125, ?", "Chaque colonne utilise une puissance impaire du premier nombre.", ["3125", "625", "1250", "1500"], "Le motif de lignes est n¹, n³, n⁵. Rangée 3 : 5¹=5, 5³=125, 5⁵=3125."],
    "TPR5_04": ["Quelle est la prochaine étape ? 4, 6, 10, 14, 22, 26, ?", "Chaque terme est deux fois un nombre premier. Quelles primes ?", ["34", "30", "32", "38"], "Chaque terme est 2 × un nombre premier consécutif : 2×2=4, 2×3=6, 2×5=10, 2×7=14, 2×11=22, 2×13=26, 2×17=34."],
    "TPR5_05": ["Quelle est la prochaine étape ? 0, 0, 1, 1, 2, 4, 7, 13, ?", "Chaque terme est la somme des trois termes précédents.", ["24", "20", "26", "19"], "C'est la série Tribonacci : chaque terme = la somme des trois qui le précèdent. 4 + 7 + 13 = 24."],
    "TPR5_06": ["Quelle est la prochaine étape ? 2, 12, 36, 80, 150, ?", "Essayez d'exprimer chaque terme sous la forme n²(n + 1).", ["252", "210", "240", "260"], "Chaque terme est n²(n+1) : 1²×2=2, 2²×3=12, 3²×4=36, 4²×5=80, 5²×6=150, 6²×7=252."],
    "TPR5_07": ["Grille : 1, 2, 5/2, 3, 13/4, 5, ?", "Essayez les carrés des deux premières colonnes ajoutées.", ["41", "20", "45", "36"], "Colonne 3 = colonne 1² + colonne 2². Rangée 3 : 4² + 5² = 16 + 25 = 41."],
    "TPR5_08": ["Quelle est la prochaine étape ? 2, 8, 18, 32, 50, ?", "Essayez d'exprimer chaque terme sous la forme 2n² pendant n consécutifs.", ["72", "60", "68", "80"], "Chaque terme est 2n² : 2(1²)=2, 2(2²)=8, 2(3²)=18, 2(4²)=32, 2(5²)=50, 2(6²)=72."],
    "TPR5_09": ["Quelle est la prochaine étape ? 2, 4, 16, 256, ?", "Chaque terme est le carré du terme précédent.", ["65536", "512", "1024", "4096"], "Chaque terme = précédent². 2²=4, 4²=16, 16²=256, 256²=65536."],
    "TPR5_10": ["Quelle est la prochaine étape ? 47, 43, 41, 37, 31, 29, ?", "Ce sont des nombres premiers par ordre décroissant.", ["23", "27", "25", "19"], "La chaîne répertorie les nombres premiers consécutifs par ordre décroissant. Après 29, le prochain plus petit nombre premier est 23."],
    "TPR5_11": ["Grille : 2, 3, 7/4, 5, 21/6, 7, ?", "Multipliez les deux premières colonnes et ajustez par 1.", ["43", "42", "44", "40"], "Colonne 3 = colonne 1 × colonne 2 + 1. Ligne 3 : 6 × 7 + 1 = 43."],
    "TPR5_12": ["Quelle est la prochaine étape ? 1, 5, 12, 22, 35, ?", "Ce sont des nombres pentagonaux : n(3n − 1)/2.", ["51", "48", "50", "55"], "Nombres pentagonaux : n(3n−1)/2. Pour n=6 : 6×17/2 = 51."],
    "TPR5_13": ["Quelle est la prochaine étape ? 2, 6, 30, 210, ?", "Chaque terme est multiplié par le nombre premier suivant.", ["2310", "1470", "1260", "1890"], "2×3=6, 6×5=30, 30×7=210, 210×11=2310. À chaque étape, vous multipliez par le nombre premier suivant."],
    "TPR5_14": ["Grille : 4, 16, 64/6, 36, 216/8, 64, ?", "Chaque ligne montre les puissances du premier nombre.", ["512", "256", "480", "128"], "Le modèle de ligne est n¹, n², n³. Rangée 3 : 8, 64, 512."],
    "TPR5_15": ["Quelle est la prochaine étape ? 1, 3, 11, 43, ?", "Chaque terme est multiplié par 4 et diminué de 1.", ["171", "170", "172", "160"], "Chaque terme = précédent × 4 − 1 : 1→3, 3→11, 11→43, 43→171."],
    "TPR5_16": ["Quelle est la prochaine étape ? 59, 53, 47, 43, 41, 37, ?", "Ce sont des nombres premiers par ordre décroissant.", ["31", "33", "29", "35"], "La chaîne répertorie les nombres premiers consécutifs dans l'ordre inverse. Après 37, le prochain plus petit nombre premier est 31."],
    "TPR5_17": ["Quelle est la prochaine étape ? 27, 125, 343, 729, ?", "Chaque terme est le cube d’un entier impair consécutif — lequel ?", ["1331", "1000", "1200", "1500"], "Ce sont des cubes de nombres impairs consécutifs : 3³=27, 5³=125, 7³=343, 9³=729, 11³=1331."],
    "TPR5_18": ["Grille : 3, 2, 18/4, 3, 48/5, 4, ?", "Essayez de mettre au carré la colonne 1 multipliée par la colonne 2.", ["100", "80", "60", "125"], "Colonne 3 = colonne 1² × colonne 2. Ligne 3 : 5² × 4 = 25 × 4 = 100."],
    "TPR5_19": ["Quelle est la prochaine étape ? 2, 3, 6, 7, 14, 15, ?", "La chaîne alterne entre deux opérations.", ["30", "16", "28", "22"], "Le motif alterne +1 et ×2 : 2+1=3, 3×2=6, 6+1=7, 7×2=14, 14+1=15, 15×2=30."],
    "TPR5_20": ["Quelle est la prochaine étape ? 1, 9, 36, 100, 225, ?", "Chaque terme est un carré parfait. À quels chiffres sont-ils élevés ?", ["441", "400", "484", "500"], "Ce sont des carrés de sommes cumulées : (1)²=1, (1+2)²=9, (1+2+3)²=36, (1+2+3+4)²=100, (1+2+3+4+5)²=225, (1+2+3+4+5+6)²=441."],
    "TNR1_01": ["Que vient ensuite la chaîne : 7, 8, 9, 10, 11, ?", "Regardez la différence entre chaque paire de termes consécutifs.", ["12", "13", "10", "14"], "Chaque terme augmente de 1. Le terme suivant est 11 + 1 = 12."],
    "TNR1_02": ["Qu'est-ce qui vient ensuite dans la chaîne : 3, 5, 7, 9, 11, ?", "Soustrayez chaque terme du suivant.", ["13", "12", "14", "15"], "Chaque terme augmente de 2. Le terme suivant est 11 + 2 = 13."],
    "TNR1_03": ["Que vient ensuite la chaîne : 10, 13, 16, 19, 22, ?", "Trouve la différence constante entre des termes consécutifs.", ["25", "24", "26", "23"], "Chaque terme augmente de 3. Le terme suivant est 22 + 3 = 25."],
    "TNR1_04": ["Que vient ensuite la chaîne : 1, 5, 9, 13, 17, ?", "De combien chaque terme augmente-t-il par rapport au précédent ?", ["21", "20", "22", "19"], "Chaque terme augmente de 4. Le terme suivant est 17 + 4 = 21."],
    "TNR1_05": ["Que vient ensuite la chaîne : 2, 7, 12, 17, 22, ?", "Calcule le pas entre des termes consécutifs.", ["27", "25", "28", "26"], "Chaque terme augmente de 5. Le terme suivant est 22 + 5 = 27."],
    "TNR1_06": ["Que vient ensuite la chaîne : 4, 10, 16, 22, 28, ?", "Qu'est-ce qui est ajouté à chaque fois ?", ["34", "32", "36", "30"], "Chaque terme augmente de 6. Le terme suivant est 28 + 6 = 34."],
    "TNR1_07": ["Que vient ensuite la chaîne : 3, 10, 17, 24, 31, ?", "Trouvez la constante ajoutée à chaque terme.", ["38", "35", "39", "37"], "Chaque terme augmente de 7. Le terme suivant est 31 + 7 = 38."],
    "TNR1_08": ["Que vient ensuite la chaîne : 5, 13, 21, 29, 37, ?", "Soustrayez le premier terme du second pour trouver la taille du pas.", ["45", "44", "46", "43"], "Chaque terme augmente de 8. Le terme suivant est 37 + 8 = 45."],
    "TNR1_09": ["Que vient ensuite la chaîne : 2, 11, 20, 29, 38, ?", "Quel numéro est ajouté à chaque étape ?", ["47", "45", "48", "46"], "Chaque terme augmente de 9. Le terme suivant est 38 + 9 = 47."],
    "TNR1_10": ["Que vient ensuite la chaîne : 6, 16, 26, 36, 46, ?", "Regardez l'intervalle entre deux termes consécutifs.", ["56", "54", "58", "52"], "Chaque terme augmente de 10. Le terme suivant est 46 + 10 = 56."],
    "TNR1_11": ["Que vient ensuite la chaîne : 20, 19, 18, 17, 16, ?", "La chaîne diminue. Combien à chaque étape ?", ["15", "14", "17", "13"], "Chaque terme diminue de 1. Le terme suivant est 16 − 1 = 15."],
    "TNR1_12": ["Que vient ensuite la chaîne : 30, 28, 26, 24, 22, ?", "Soustrayez chaque terme de celui qui le précède.", ["20", "21", "18", "19"], "Chaque terme diminue de 2. Le terme suivant est 22 − 2 = 20."],
    "TNR1_13": ["Que vient ensuite la chaîne : 40, 37, 34, 31, 28, ?", "La chaîne diminue. Trouvez votre rythme régulier.", ["25", "26", "24", "27"], "Chaque terme diminue de 3. Le terme suivant est 28 − 3 = 25."],
    "TNR1_14": ["Que vient ensuite la chaîne : 50, 46, 42, 38, 34, ?", "De combien diminue-t-il à chaque fois ?", ["30", "32", "28", "31"], "Chaque terme diminue de 4. Le terme suivant est 34 − 4 = 30."],
    "TNR1_15": ["Que vient ensuite la chaîne : 60, 55, 50, 45, 40, ?", "Trouvez le pas fixe entre deux termes consécutifs.", ["35", "30", "38", "33"], "Chaque terme diminue de 5. Le terme suivant est 40 − 5 = 35."],
    "TNR1_16": ["Que vient ensuite la chaîne : 5, 16, 27, 38, 49, ?", "Calculez la différence entre les deux premiers termes et vérifiez si elle reste la même.", ["60", "58", "61", "55"], "Chaque terme augmente de 11. Le terme suivant est 49 + 11 = 60."],
    "TNR1_17": ["Que vient ensuite la chaîne : 3, 15, 27, 39, 51, ?", "Quelle est la constante ajoutée à chaque étape ?", ["63", "60", "64", "62"], "Chaque terme augmente de 12. Le terme suivant est 51 + 12 = 63."],
    "TNR1_18": ["Que vient ensuite la chaîne : 10, 25, 40, 55, 70, ?", "Trouvez le pas fixe ajouté entre les termes.", ["85", "80", "90", "75"], "Chaque terme augmente de 15. Le terme suivant est 70 + 15 = 85."],
    "TNR1_19": ["Qu'est-ce qui vient ensuite dans la chaîne : 5, 25, 45, 65, 85, ?", "Calculez le pas d'un terme au suivant.", ["105", "100", "110", "95"], "Chaque terme augmente de 20. Le terme suivant est 85 + 20 = 105."],
    "TNR1_20": ["Que vient ensuite la chaîne : 42, 36, 30, 24, 18, ?", "La chaîne diminue. Qu’est-ce qui est soustrait à chaque fois ?", ["12", "14", "10", "16"], "Chaque terme diminue de 6. Le terme suivant est 18 − 6 = 12."],
    "TNR2_01": ["Qu'est-ce qui vient ensuite dans la chaîne : 5, 10, 20, 40, 80, ?", "Essayez de diviser chaque terme par le précédent.", ["160", "120", "140", "100"], "Chaque terme est multiplié par 2. Le terme suivant est 80 × 2 = 160."],
    "TNR2_02": ["Que vient ensuite la chaîne : 2, 6, 18, 54, 162, ?", "Quel est le rapport des termes consécutifs ?", ["486", "324", "480", "648"], "Chaque terme est multiplié par 3. Le terme suivant est 162 × 3 = 486."],
    "TNR2_03": ["Que vient ensuite la chaîne : 1, 4, 16, 64, 256, ?", "Divisez le deuxième terme par le premier pour trouver le multiplicateur.", ["1024", "512", "768", "1280"], "Chaque terme est multiplié par 4. Le terme suivant est 256 × 4 = 1024."],
    "TNR2_04": ["Que vient ensuite la chaîne : 2, 10, 50, 250, 1250, ?", "Regardez le ratio de termes consécutifs.", ["6250", "5000", "6000", "7500"], "Chaque terme est multiplié par 5. Le terme suivant est 1 250 × 5 = 6 250."],
    "TNR2_05": ["Que vient ensuite la chaîne : 3, 30, 300, 3000, 30000, ?", "Chaque terme reçoit un autre zéro. Par quoi se multiplie-t-il ?", ["300000", "60000", "200 000", "330000"], "Chaque terme est multiplié par 10. Le terme suivant est 30 000 × 10 = 300 000."],
    "TNR2_06": ["Que vient ensuite la chaîne : 640, 320, 160, 80, 40, ?", "La chaîne est réduite de moitié. Quelle opération est appliquée à chaque étape ?", ["20", "10", "30", "25"], "Chaque terme est divisible par 2. Le terme suivant est 40 ÷ 2 = 20."],
    "TNR2_07": ["Que vient ensuite la chaîne : 729, 243, 81, 27, 9, ?", "Essayez de diviser chaque terme en suivant.", ["3", "6", "1", "4"], "Chaque terme est divisible par 3. Le terme suivant est 9 ÷ 3 = 3."],
    "TNR2_08": ["Que vient ensuite la chaîne : 192, 96, 48, 24, 12, ?", "Quelle fraction du terme précédent donne le terme actuel ?", ["6", "4", "8", "3"], "Chaque terme est divisible par 2. Le terme suivant est 12 ÷ 2 = 6."],
    "TNR2_09": ["Qu'est-ce qui vient ensuite dans la chaîne : 3, 4, 7, 11, 18, ?", "Essayez d'ajouter deux termes consécutifs.", ["29", "25", "27", "30"], "Chaque terme est la somme des deux qui le précèdent : 11 + 18 = 29."],
    "TNR2_10": ["Qu'est-ce qui vient ensuite dans la chaîne : 2, 5, 7, 12, 19, ?", "Regardez comment chaque terme est lié aux deux qui le précèdent.", ["31", "26", "28", "33"], "Chaque terme est la somme des deux qui le précèdent : 12 + 19 = 31."],
    "TNR2_11": ["Que vient ensuite la chaîne : 4, 9, 19, 39, 79, ?", "Essayez de doubler un terme, puis de l'ajuster d'un petit nombre.", ["159", "158", "160", "149"], "Chaque terme suit la règle : précédent × 2 + 1. Le terme suivant est 79 × 2 + 1 = 159."],
    "TNR2_12": ["Que vient ensuite la chaîne : 4, 12, 36, 108, 324, ?", "Divisez chaque terme par le terme précédent pour trouver un rapport constant.", ["972", "648", "1296", "900"], "Chaque terme est multiplié par 3. Le terme suivant est 324 × 3 = 972."],
    "TNR2_13": ["Que vient ensuite la chaîne : 7, 14, 28, 56, 112, ?", "Que se passe-t-il lorsque vous divisez chaque terme par le terme qui le précède ?", ["224", "168", "220", "228"], "Chaque terme est multiplié par 2. Le terme suivant est 112 × 2 = 224."],
    "TNR2_14": ["Que vient ensuite la chaîne : 1, 3, 4, 7, 11, ?", "Vérifiez si chaque terme est la somme des deux qui le précèdent.", ["18", "15", "16", "20"], "Chaque terme est la somme des deux qui le précèdent : 7 + 11 = 18."],
    "TNR2_15": ["Que vient ensuite la chaîne : 256, 128, 64, 32, 16, ?", "Ce sont toutes des puissances de 2. Quel diviseur relie chaque paire ?", ["8", "4", "12", "10"], "Chaque terme est divisible par 2. Le terme suivant est 16 ÷ 2 = 8."],
    "TNR2_16": ["Que vient ensuite la chaîne : 1, 5, 25, 125, 625, ?", "Trouvez le multiplicateur en divisant n'importe quel terme par le terme précédent.", ["3125", "1250", "3000", "3750"], "Chaque terme est multiplié par 5. Le terme suivant est 625 × 5 = 3125."],
    "TNR2_17": ["Que vient ensuite la chaîne : 3, 8, 18, 38, 78, ?", "Essayez de doubler le terme précédent et d'ajouter une petite constante.", ["158", "156", "160", "148"], "Chaque terme suit la règle : précédent × 2 + 2. Le terme suivant est 78 × 2 + 2 = 158."],
    "TNR2_18": ["Que vient ensuite la chaîne : 1, 4, 5, 9, 14, ?", "Voyez si la somme de deux termes consécutifs donne ce qui suit.", ["23", "19", "21", "25"], "Chaque terme est la somme des deux qui le précèdent : 9 + 14 = 23."],
    "TNR2_19": ["Que vient ensuite la chaîne : 2187, 729, 243, 81, 27, ?", "Chaque terme est une fraction du précédent. Quel diviseur est utilisé ?", ["9", "3", "18", "12"], "Chaque terme est divisible par 3. Le terme suivant est 27 ÷ 3 = 9."],
    "TNR2_20": ["Que vient ensuite la chaîne : 2, 8, 32, 128, 512, ?", "Divisez les termes consécutifs pour trouver le multiplicateur constant.", ["2048", "1024", "2560", "1536"], "Chaque terme est multiplié par 4. Le terme suivant est 512 × 4 = 2048."],
    "TNR3_01": ["Que vient ensuite la chaîne : 36, 49, 64, 81, 100, ?", "Essayez la racine carrée de chaque terme.", ["121", "110", "120", "125"], "Ce sont des carrés parfaits consécutifs : 6²=36, 7²=49, 8²=64, 9²=81, 10²=100, 11²=121."],
    "TNR3_02": ["Que vient ensuite la chaîne : 100, 121, 144, 169, 196, ?", "Chaque terme est un carré parfait. De quels carrés s'agit-il ?", ["225", "220", "230", "216"], "Ce sont des carrés parfaits consécutifs : 10²=100, 11²=121, 12²=144, 13²=169, 14²=196, 15²=225."],
    "TNR3_03": ["Que vient ensuite la chaîne : 125, 216, 343, 512, 729, ?", "Essayez la racine cubique de chaque terme.", ["1000", "900", "1024", "972"], "Ce sont des cubes parfaits consécutifs : 5³=125, 6³=216, 7³=343, 8³=512, 9³=729, 10³=1000."],
    "TNR3_04": ["Que vient ensuite la chaîne : 343, 512, 729, 1000, 1331, ?", "Ce sont des cubes d'entiers consécutifs. Quels entiers ?", ["1728", "1500", "1700", "2000"], "Ce sont des cubes parfaits consécutifs : 7³=343, 8³=512, 9³=729, 10³=1000, 11³=1331, 12³=1728."],
    "TNR3_05": ["Que vient ensuite la chaîne : 10, 12, 16, 22, 30, ?", "Calculez les différences entre les termes. Ces différences forment-elles un modèle ?", ["40", "38", "42", "36"], "Les différences sont de 2, 4, 6, 8 — augmentant de 2 à chaque étape. La différence suivante est de 10, donc 30 + 10 = 40."],
    "TNR3_06": ["Que vient ensuite la chaîne : 7, 10, 16, 25, 37, ?", "Trouvez les différences entre les termes, puis recherchez une tendance dans ces différences.", ["52", "49", "55", "46"], "Les différences sont 3, 6, 9, 12 – augmentant de 3 à chaque étape. La différence suivante est 15, donc 37 + 15 = 52."],
    "TNR3_07": ["Qu'est-ce qui vient ensuite dans la chaîne : 5, 6, 9, 14, 21, ?", "Les différences entre les termes sont des nombres impairs consécutifs.", ["30", "28", "32", "27"], "Les différences sont 1, 3, 5, 7 — nombres impairs consécutifs. La différence suivante est 9, donc 21 + 9 = 30."],
    "TNR3_08": ["Qu'est-ce qui vient ensuite dans la chaîne : 5, 7, 11, 13, 17, ?", "Pensez aux nombres qui ont exactement deux diviseurs.", ["19", "18", "21", "20"], "Ce sont des nombres premiers consécutifs commençant à 5. Le nombre premier suivant après 17 est 19."],
    "TNR3_09": ["Que vient ensuite la chaîne : 11, 13, 17, 19, 23, ?", "Ces nombres sont-ils divisibles uniquement par 1 et par eux-mêmes ?", ["29", "27", "25", "31"], "Ce sont des nombres premiers consécutifs commençant à 11. Le nombre premier suivant après 23 est 29."],
    "TNR3_10": ["Que vient ensuite la chaîne : 4, 16, 36, 64, 100, ?", "Extrayez la racine carrée de chaque terme. Quel est le point commun entre ces chiffres ?", ["144", "128", "136", "148"], "Ce sont des carrés de nombres pairs consécutifs : 2²=4, 4²=16, 6²=36, 8²=64, 10²=100, 12²=144."],
    "TNR3_11": ["Que vient ensuite la chaîne : 1, 9, 25, 49, 81, ?", "Extrayez la racine carrée de chaque terme. De quel type de chiffres s’agit-il ?", ["121", "100", "110", "125"], "Ce sont des carrés de nombres impairs consécutifs : 1²=1, 3²=9, 5²=25, 7²=49, 9²=81, 11²=121."],
    "TNR3_12": ["Que vient ensuite la chaîne : 2, 5, 10, 17, 26, ?", "Soustrayez 1 à chaque terme. Les résultats vous semblent-ils familiers ?", ["37", "35", "36", "39"], "Chaque terme est n² + 1 : 1²+1=2, 2²+1=5, 3²+1=10, 4²+1=17, 5²+1=26, 6²+1=37."],
    "TNR3_13": ["Que vient ensuite la chaîne : 0, 3, 8, 15, 24, ?", "Ajoutez 1 à chaque terme. Quelle chaîne connue obtenez-vous ?", ["35", "33", "36", "30"], "Chaque terme est n² − 1 : 1²−1=0, 2²−1=3, 3²−1=8, 4²−1=15, 5²−1=24, 6²−1=35."],
    "TNR3_14": ["Qu'est-ce qui vient ensuite dans la chaîne : 5, 9, 17, 29, 45, ?", "Calculez les écarts, puis vérifiez s’ils augmentent régulièrement.", ["65", "61", "69", "57"], "Les différences sont de 4, 8, 12, 16 — augmentant de 4 à chaque étape. La différence suivante est de 20, donc 45 + 20 = 65."],
    "TNR3_15": ["Que vient ensuite la chaîne : 2, 9, 28, 65, 126, ?", "Soustrayez 1 à chaque terme. Quel genre de chiffres reste-t-il ?", ["217", "215", "220", "210"], "Chaque terme est n³ + 1 : 1³+1=2, 2³+1=9, 3³+1=28, 4³+1=65, 5³+1=126, 6³+1=217."],
    "TNR3_16": ["Que vient ensuite la chaîne : 3, 8, 15, 24, 35, ?", "Essayez d'exprimer chaque terme comme le produit de deux nombres adjacents.", ["48", "46", "50", "44"], "Chaque terme est n(n + 2) : 1×3=3, 2×4=8, 3×5=15, 4×6=24, 5×7=35, 6×8=48."],
    "TNR3_17": ["Que vient ensuite la chaîne : 1, 5, 11, 19, 29, ?", "Les différences entre les termes augmentent avec une constante. Trouvez cette constante.", ["41", "39", "43", "37"], "Les différences sont de 4, 6, 8, 10 — augmentant de 2 à chaque étape. La différence suivante est 12, donc 29 + 12 = 41."],
    "TNR3_18": ["Que vient ensuite la chaîne : 2, 8, 18, 32, 50, ?", "Essayez de diviser chaque terme par 2. Les résultats vous semblent-ils familiers ?", ["72", "68", "74", "64"], "Chaque terme est 2n² : 2(1²)=2, 2(2²)=8, 2(3²)=18, 2(4²)=32, 2(5²)=50, 2(6²)=72."],
    "TNR3_19": ["Que vient ensuite la chaîne : 4, 7, 12, 19, 28, ?", "Soustrayez 3 de chaque terme. Quelle chaîne reconnaissez-vous ?", ["39", "37", "41", "36"], "Chaque terme est n² + 3 : 1²+3=4, 2²+3=7, 3²+3=12, 4²+3=19, 5²+3=28, 6²+3=39."],
    "TNR3_20": ["Que vient ensuite la chaîne : 4, 9, 19, 34, 54, ?", "Trouvez les différences, puis les différences de ces différences.", ["79", "74", "84", "69"], "Les différences sont de 5, 10, 15, 20 — augmentant de 5 à chaque étape. La différence suivante est de 25, donc 54 + 25 = 79."],
    "TNR4_01": ["Que vient ensuite la chaîne : 2, 3, 7, 25, 121, ?", "Soustrayez 1 à chaque terme et voyez si vous reconnaissez les nombres.", ["721", "720", "625", "719"], "Chaque terme est n! + 1 : 1!+1=2, 2!+1=3, 3!+1=7, 4!+1=25, 5!+1=121, 6!+1=721."],
    "TNR4_02": ["Que vient ensuite la chaîne : 0, 1, 5, 23, 119, ?", "Ajoutez 1 à chaque terme. Reconnaissez-vous les nombres résultants ?", ["719", "720", "600", "721"], "Chaque terme est n! − 1 : 1!−1=0, 2!−1=1, 3!−1=5, 4!−1=23, 5!−1=119, 6!−1=719."],
    "TNR4_03": ["Que vient ensuite la chaîne : 15, 21, 28, 36, 45, ?", "Ce sont des nombres triangulaires. Les différences entre les termes augmentent de 1 à chaque étape.", ["55", "54", "56", "50"], "Nombres triangulaires T(5) – T(10). Les différences sont 6, 7, 8, 9, donc la suivante est 10 : 45 + 10 = 55."],
    "TNR4_04": ["Que vient ensuite la chaîne : 36, 45, 55, 66, 78, ?", "Calculez les différences. Ils augmentent de 1 à chaque fois — signe des nombres triangulaires.", ["91", "88", "90", "84"], "Nombres triangulaires T(8) – T(13). Les différences sont 9, 10, 11, 12, donc la suivante est 13 : 78 + 13 = 91."],
    "TNR4_05": ["Que vient ensuite la chaîne : 1, 5, 13, 29, 61, ?", "Essayez de doubler le terme précédent et d'ajouter une petite constante.", ["125", "122", "123", "127"], "Chaque terme suit la règle : précédent × 2 + 3. Le terme suivant est 61 × 2 + 3 = 125."],
    "TNR4_06": ["Que vient ensuite la chaîne : 1, 2, 5, 14, 41, ?", "Essayez de multiplier le terme précédent par 3 et d'ajuster.", ["122", "120", "123", "82"], "Chaque terme suit la règle : précédent × 3 − 1. Le terme suivant est 41 × 3 − 1 = 122."],
    "TNR4_07": ["Que vient ensuite la chaîne : 2, 9, 23, 51, 107, ?", "Doublez le terme précédent et ajoutez une constante pour obtenir le suivant.", ["219", "214", "215", "221"], "Chaque terme suit la règle : précédent × 2 + 5. Le terme suivant est 107 × 2 + 5 = 219."],
    "TNR4_08": ["Que vient ensuite la chaîne : 9, 25, 49, 121, 169, ?", "Prenez la racine carrée de chaque terme, puis réfléchissez à la particularité de ces nombres.", ["289", "225", "256", "324"], "Ce sont des carrés de nombres premiers consécutifs : 3²=9, 5²=25, 7²=49, 11²=121, 13²=169, 17²=289."],
    "TNR4_09": ["Que vient ensuite la chaîne : 10, 11, 15, 24, 40, ?", "Trouvez les différences entre les termes. Ces différences sont-elles une chaîne connue ?", ["65", "56", "64", "60"], "Les différences sont 1, 4, 9, 16 — carrés parfaits (1², 2², 3², 4²). La différence suivante est 5²=25, donc 40 + 25 = 65."],
    "TNR4_10": ["Que vient ensuite la chaîne : 0, 1, 3, 9, 33, ?", "Calculez les différences entre les termes. Ces écarts vous évoquent-ils une suite bien connue ?", ["153", "129", "150", "57"], "Les différences sont 1, 2, 6, 24 — c'est-à-dire factorielles (1 !, 2 !, 3 !, 4 !). La différence suivante est 5 !=120, donc 33 + 120 = 153."],
    "TNR4_11": ["Que vient ensuite la chaîne : 2, 7, 22, 67, 202, ?", "Multipliez le terme précédent par un nombre et ajoutez une constante.", ["607", "606", "605", "610"], "Chaque terme suit la règle : précédent × 3 + 1. Le terme suivant est 202 × 3 + 1 = 607."],
    "TNR4_12": ["Que vient ensuite la chaîne : 20, 37, 71, 139, 275, ?", "Essayez de doubler le terme précédent et de soustraire une petite constante.", ["547", "550", "545", "553"], "Chaque terme suit la règle : précédent × 2 − 3. Le terme suivant est 275 × 2 − 3 = 547."],
    "TNR4_13": ["Que vient ensuite la chaîne : 1, 5, 14, 30, 55, ?", "Les différences entre les termes sont des carrés parfaits. Ajoutez des carrés consécutifs.", ["91", "85", "90", "80"], "Ce sont des sommes cumulées de carrés : 1, 1+4=5, 5+9=14, 14+16=30, 30+25=55, 55+36=91."],
    "TNR4_14": ["Que vient ensuite la chaîne : 2, 4, 12, 48, 240, ?", "Essayez de diviser chaque terme par 2. Les résultats semblent-ils factoriels ?", ["1440", "1200", "1680", "960"], "Chaque terme est 2 × n ! : 2 × 1 ! = 2, 2 × 2 ! = 4, 2 × 3 ! = 12, 2 × 4 ! = 48, 2 × 5 ! = 240, 2 × 6 ! = 1440."],
    "TNR4_15": ["Que vient ensuite la chaîne : 6, 13, 27, 55, 111, ?", "Doublez le terme précédent et ajoutez une constante à chaque étape.", ["223", "222", "220", "225"], "Chaque terme suit la règle : précédent × 2 + 1. Le terme suivant est 111 × 2 + 1 = 223."],
    "TNR4_16": ["Que vient ensuite la chaîne : 10, 11, 14, 20, 30, ?", "Les différences entre les termes sont des nombres triangulaires : 1, 3, 6, 10, …", ["45", "40", "42", "50"], "Les différences sont 1, 3, 6, 10 — nombres triangulaires. Le prochain nombre triangulaire est 15, donc 30 + 15 = 45."],
    "TNR4_17": ["Que vient ensuite la chaîne : 12, 20, 30, 42, 56, ?", "Essayez d'exprimer chaque terme comme le produit de deux nombres entiers consécutifs.", ["72", "68", "70", "64"], "Ce sont n(n+1) nombres oblongs : 3×4=12, 4×5=20, 5×6=30, 6×7=42, 7×8=56, 8×9=72."],
    "TNR4_18": ["Que vient ensuite la chaîne : 1, 9, 36, 100, 225, ?", "Chaque terme est le carré d'un nombre triangulaire, ou de manière équivalente la somme cubique cumulée.", ["441", "400", "440", "450"], "Ce sont des sommes de cubes consécutifs : 1³=1, 1+8=9, 9+27=36, 36+64=100, 100+125=225, 225+216=441."],
    "TNR4_19": ["Que vient ensuite la chaîne : 3, 7, 19, 55, 163, ?", "Multipliez le terme précédent par un nombre et soustrayez une constante.", ["487", "489", "485", "492"], "Chaque terme suit la règle : précédent × 3 − 2. Le terme suivant est 163 × 3 − 2 = 487."],
    "TNR4_20": ["Que vient ensuite la chaîne : 12, 23, 45, 89, 177, ?", "Doublez le terme précédent et faites un petit ajustement.", ["353", "354", "355", "350"], "Chaque terme suit la règle : précédent × 2 − 1. Le terme suivant est 177 × 2 − 1 = 353."],
    "TNR5_01": ["Que vient ensuite la chaîne : 1, 2, 9, 64, 625, ?", "Pensez à la puissance avec laquelle la base est soulevée à partir de chaque position.", ["7776", "7774", "7200", "3125"], "Chaque terme est n élevé à la puissance (n−1) : 1⁰=1, 2¹=2, 3²=9, 4³=64, 5⁴=625, 6⁵=7776."],
    "TNR5_02": ["Que vient ensuite la chaîne : 2, 10, 30, 68, 130, ?", "Essayez de diviser chaque terme en une partie cubique et une partie linéaire.", ["222", "220", "218", "216"], "Chaque terme est n³ + n : 1+1=2, 8+2=10, 27+3=30, 64+4=68, 125+5=130, 216+6=222."],
    "TNR5_03": ["Que vient ensuite la chaîne : 1, 1, 2, 5, 14, ?", "Ce sont les chiffres catalans. Chaque C(n) = C(0)C(n−1) + C(1)C(n−2) + … + C(n−1)C(0).", ["42", "28", "35", "48"], "Nombres catalans : C(0)=1, C(1)=1, C(2)=2, C(3)=5, C(4)=14, C(5)=42."],
    "TNR5_04": ["Que vient ensuite la chaîne : 1, 5, 12, 22, 35, ?", "Les différences sont 4, 7, 10, 13 — progression arithmétique par étape 3.", ["51", "48", "50", "55"], "Ce sont des nombres pentagonaux : n(3n−1)/2. Pour n=6 : 6×17/2 = 51."],
    "TNR5_05": ["Que vient ensuite la chaîne : 2, 5, 13, 35, 97, ?", "Essayez d'exprimer chaque terme comme la somme de deux exponentielles.", ["275", "265", "270", "280"], "Chaque terme est 2ⁿ + 3ⁿ (à partir de n=0) : 1+1=2, 2+3=5, 4+9=13, 8+27=35, 16+81=97, 32+243=275."],
    "TNR5_06": ["Que vient ensuite la chaîne : 1, 5, 17, 53, 161, ?", "Multipliez le terme précédent par 3 et ajoutez une petite constante.", ["485", "483", "322", "487"], "Chaque terme suit la règle : précédent × 3 + 2. Le terme suivant est 161 × 3 + 2 = 485."],
    "TNR5_07": ["Que vient ensuite la chaîne : 1, 2, 5, 12, 27, ?", "Pensez aux puissances de 2, puis soustrayez quelque chose qui dépend de la position.", ["58", "54", "56", "60"], "Chaque terme est 2ⁿ − n : 2¹−1=1, 2²−2=2, 2³−3=5, 2⁴−4=12, 2⁵−5=27, 2⁶−6=58."],
    "TNR5_08": ["Que vient ensuite la chaîne : 2, 12, 36, 80, 150, ?", "Essayez de factoriser chaque terme comme n² multiplié par quelque chose.", ["252", "240", "250", "260"], "Chaque terme est n²(n+1) : 1×2=2, 4×3=12, 9×4=36, 16×5=80, 25×6=150, 36×7=252."],
    "TNR5_09": ["Que vient ensuite la chaîne : 1, 6, 15, 28, 45, ?", "Les différences sont 5, 9, 13, 17 — augmentent de 4. Ce sont des nombres hexagonaux.", ["66", "60", "63", "70"], "Nombres hexagonaux : n(2n−1). Pour n=6 : 6×11 = 66."],
    "TNR5_10": ["Que vient ensuite la chaîne : 2, 6, 15, 40, 145, ?", "Essayez de diviser chaque terme en une partie factorielle et une partie quadratique.", ["756", "750", "745", "760"], "Chaque terme est n! + n² : 1!+1=2, 2!+4=6, 3!+9=15, 4!+16=40, 5!+25=145, 6!+36=756."],
    "TNR5_11": ["Que vient ensuite la chaîne : 2, 4, 7, 14, 17, ?", "Les opérations alternent entre deux règles différentes à des pas impairs et pairs.", ["34", "20", "31", "37"], "Le motif alterne : ×2, +3, ×2, +3, ×2. Donc 17 × 2 = 34."],
    "TNR5_12": ["Que vient ensuite la chaîne : 1, 5, 19, 65, 211, ?", "Exprimez chaque terme comme la différence de deux exponentielles.", ["665", "660", "633", "670"], "Chaque terme est 3ⁿ − 2ⁿ : 3−2=1, 9−4=5, 27−8=19, 81−16=65, 243−32=211, 729−64=665."],
    "TNR5_13": ["Que vient ensuite la chaîne : 1, 4, 11, 29, 76, ?", "Chaque terme dépend des deux qui le précèdent. Essayez une combinaison linéaire.", ["199", "197", "200", "228"], "La règle est a(n) = 3×a(n−1) − a(n−2) : 3×29−11=76, 3×76−29=199."],
    "TNR5_14": ["Que vient ensuite la chaîne : 20, 22, 26, 34, 50, ?", "Les différences sont 2, 4, 8, 16 — puissances de 2.", ["82", "66", "80", "84"], "Les différences sont des puissances de 2 : 2, 4, 8, 16. La différence suivante est 32, donc 50 + 32 = 82."],
    "TNR5_15": ["Que vient ensuite la chaîne : 1, 4, 10, 20, 35, ?", "Ce sont des nombres tétraédriques – sommes de nombres triangulaires consécutifs.", ["56", "50", "55", "60"], "Nombres tétraédriques : n(n+1)(n+2)/6. Pour n=6 : 6×7×8/6 = 56."],
    "TNR5_16": ["Que vient ensuite la chaîne : 1, 13, 37, 73, 121, ?", "Les différences sont 12, 24, 36, 48 — multiples de 12.", ["181", "169", "175", "193"], "Ce sont des nombres d'étoiles : 6n(n−1)+1. Pour n=6 : 6×30+1 = 181."],
    "TNR5_17": ["Que vient ensuite la chaîne : 1, 7, 19, 37, 61, ?", "Les différences sont 6, 12, 18, 24 — multiples de 6.", ["91", "85", "90", "97"], "Ce sont des nombres hexagonaux centrés : 3n(n−1)+1. Pour n=6 : 3×30+1 = 91."],
    "TNR5_18": ["Que vient ensuite la chaîne : 3, 8, 17, 32, 57, ?", "Essayez d'exprimer chaque terme comme la somme d'un carré et d'une puissance de 2.", ["100", "96", "98", "105"], "Chaque terme est n² + 2ⁿ : 1+2=3, 4+4=8, 9+8=17, 16+16=32, 25+32=57, 36+64=100."],
    "TNR5_19": ["Que vient ensuite la chaîne : 1, 4, 8, 11, 22, ?", "Deux opérations différentes alternent. L’un ajoute, l’autre multiplie.", ["25", "44", "24", "26"], "Le motif alterne : +3, ×2, +3, ×2, +3. Donc 22 + 3 = 25."],
    "TNR5_20": ["Que vient ensuite la chaîne : 1, 1, 3, 5, 11, ?", "Chaque terme utilise les deux termes précédents avec des poids différents.", ["21", "16", "22", "19"], "La règle est a(n) = a(n−1) + 2×a(n−2) : 5 + 2×3 = 11, 11 + 2×5 = 21."],
    "TLR1_01": ["Tous les médecins sont des professionnels. Le Dr Adams est médecin. Quelle conclusion pouvez-vous tirer ?", "Si tous les X sont Y et que Z est X, alors Z est Y.", ["Le Dr Adams est professionnel", "Le Dr Adams n'est pas un professionnel", "Certains professionnels ne sont pas médecins", "Tous les professionnels sont médecins"], "Tous les médecins sont des professionnels, et le Dr Adams est un médecin, donc le Dr Adams est un professionnel. Il s’agit d’un syllogisme affirmatif universel direct."],
    "TLR1_02": ["Tous les lions sont des animaux. Simba est un lion. Quelle conclusion pouvez-vous tirer ?", "Si chaque membre du groupe X appartient au groupe Y et que Simba est dans X…", ["Simba est un animal", "Tous les animaux sont des lions", "Simba n'est pas un animal", "Certains animaux ne sont pas des lions"], "Tous les lions sont des animaux, Simba est un lion, donc Simba est un animal."],
    "TLR1_03": ["Toutes les oranges sont des fruits. Cet objet est une orange. Quelle conclusion pouvez-vous tirer ?", "Si une orange est un fruit et que cet objet est une orange…", ["Cet objet est un fruit", "Tous les fruits sont des oranges", "Cet objet est végétal", "Cet article n'est peut-être pas un fruit"], "Toutes les oranges sont des fruits, cet objet est une orange, donc c'est un fruit."],
    "TLR1_04": ["Toutes les voitures sont des véhicules. Une BMW est une voiture. Quelle conclusion pouvez-vous tirer ?", "Les voitures sont un sous-ensemble de véhicules. Quelle est la place de BMW ?", ["La BMW est un véhicule", "Tous les véhicules sont des voitures", "La BMW n'est pas un véhicule", "Certains véhicules ne sont pas des voitures"], "Toutes les voitures sont des véhicules, BMW est une voiture, donc BMW est un véhicule."],
    "TLR1_05": ["Aucun oiseau n'est un insecte. Un merle est un oiseau. Quelle conclusion pouvez-vous tirer ?", "Si aucun X n’est Y et que le merle est X…", ["Un merle n'est pas un insecte", "Le merle est un insecte", "Certains insectes sont des oiseaux", "Tous les merles sont des insectes"], "Les oiseaux ne sont pas des insectes, les merles sont des oiseaux, donc les merles ne peuvent pas être des insectes."],
    "TLR1_06": ["Toute glace est froide. Le cube sur la table est fait de glace. Quelle conclusion pouvez-vous tirer ?", "Si tout ce qui est de la glace est froid et que le cube est de la glace…", ["Le cube est froid", "Le cube est chaud", "Toutes les glaces ne sont pas froides", "La table est froide"], "Toute glace est froide, le cube est de la glace, donc le cube est froid."],
    "TLR1_07": ["Tous les violons sont des instruments de musique. Un Stradivarius est un violon. Quelle conclusion pouvez-vous tirer ?", "Les violons font partie de la multitude d'instruments. Stradivarius est…", ["Stradivarius est un instrument", "Tous les instruments sont des violons", "Stradivarius n'est pas un instrument", "Certains instruments ne peuvent pas être joués"], "Tous les violons sont des instruments, le Stradivarius est un violon, donc le Stradivarius est un instrument."],
    "TLR1_08": ["Toutes les roses sont des plantes. Ce spécimen est rose. Quelle conclusion pouvez-vous tirer ?", "Les roses sont un sous-ensemble de plantes. Le spécimen est rose, donc…", ["Le spécimen est une plante", "Toutes les plantes sont des roses", "Le spécimen n'est pas une plante", "Les roses ne sont pas des plantes"], "Toutes les roses sont des plantes, ce spécimen est une rose, donc c'est une plante."],
    "TLR1_09": ["Tout l'or est métallique. Cette bague est en or. Quelle conclusion pouvez-vous tirer ?", "L'or est toujours métallique. La bague est en or, donc…", ["La bague est métallique", "Tous les corps métalliques sont dorés", "La bague n'est pas en métal", "L'or est parfois non métallique"], "Tout l'or est métallique, la bague est en or, donc la bague est métallique."],
    "TLR1_10": ["Toutes les rivières contiennent de l'eau courante. L'Amazone est un fleuve. Quelle conclusion pouvez-vous tirer ?", "Si tout fleuve a de l'eau courante et que l'Amazone est un fleuve…", ["L'Amazone contient de l'eau courante", "Toute eau courante est un fleuve", "L'Amazone ne contient pas d'eau", "Certaines rivières sont à sec"], "Toutes les rivières contiennent de l'eau courante ; l'Amazone est un fleuve, donc l'Amazone contient de l'eau courante."],
    "TLR1_11": ["Tous les romans sont des livres. Tous les livres ont des pages. Quelle conclusion pouvez-vous tirer ?", "Reliez les relations : romans → livres → pages.", ["Tous les romans ont des pages", "Toutes les pages sont exclusivement dans les romans", "Certains livres ne sont pas des romans", "Les romans n'ont pas de pages"], "Tous les romans sont des livres, tous les livres ont des pages, donc par transitivité tous les romans ont des pages."],
    "TLR1_12": ["Tous les chefs savent cuisiner. Pierre est cuisinier. Quelle conclusion pouvez-vous tirer ?", "Si tout chef sait cuisiner, et que Pierre est un chef…", ["Pierre sait cuisiner", "Quiconque sait cuisiner est un chef", "Pierre ne sait pas cuisiner", "Certains chefs ne savent pas cuisiner"], "Tous les chefs savent cuisiner, Pierre est chef, donc Pierre sait cuisiner."],
    "TLR1_13": ["Tous les aigles sont des oiseaux. Tous les oiseaux ont des plumes. Quelle conclusion pouvez-vous tirer ?", "Reliez les multitudes : aigles ⊂ oiseaux ⊂ créatures à plumes.", ["Tous les aigles ont des plumes", "Toutes les créatures volantes sont des aigles", "Les aigles n'ont pas de plumes", "Certains oiseaux ne sont pas des aigles"], "Tous les aigles sont des oiseaux, tous les oiseaux ont des plumes, donc tous les aigles ont des plumes."],
    "TLR1_14": ["Toutes les planètes tournent autour d’une étoile. Saturne est une planète. Quelle conclusion pouvez-vous tirer ?", "Les planètes tournent autour des étoiles. Saturne est une planète, donc…", ["Saturne tourne autour d'une étoile", "Tout ce qui orbite autour d'une étoile est une planète", "Saturne ne tourne pas autour d'une étoile", "L'étoile orbite autour de Saturne"], "Toutes les planètes tournent autour d’une étoile, Saturne est une planète, donc Saturne tourne autour d’une étoile."],
    "TLR1_15": ["Toutes les baleines sont des mammifères. La baleine bleue est une baleine. Quelle conclusion pouvez-vous tirer ?", "Les baleines sont un sous-ensemble des mammifères. La baleine bleue est une baleine, alors…", ["La baleine bleue est un mammifère", "Tous les mammifères sont des baleines", "La baleine bleue est un poisson", "Certaines baleines ne sont pas des mammifères"], "Toutes les baleines sont des mammifères, la baleine bleue est une baleine, donc c'est un mammifère."],
    "TLR1_16": ["Aucun herbivore ne mange de viande. Le lapin est herbivore. Quelle conclusion pouvez-vous tirer ?", "Si aucun herbivore ne mange de viande et que le lapin est herbivore…", ["Le lapin ne mange pas de viande", "Le lapin mange de la viande", "Certains herbivores mangent de la viande", "Tous les carnivores sont des lapins"], "Les herbivores ne mangent pas de viande, le lapin est herbivore, donc il ne mange pas de viande."],
    "TLR1_17": ["Tous les chiots sont des chiens. Tous les chiens sont des canidés. Quelle conclusion pouvez-vous tirer ?", "Chaîne : chiots ⊂ chiens ⊂ canidés.", ["Tous les chiots sont des canidés", "Tous les canidés sont des chiots", "Les chiots ne sont pas des chiens", "Certains chiens ne sont pas des canidés"], "Tous les chiots sont des chiens, tous les chiens sont des canidés, donc tous les chiots sont des canidés."],
    "TLR1_18": ["Tous les enseignants travaillent dans l'éducation. M. Brown est enseignant. Quelle conclusion pouvez-vous tirer ?", "Si tous les enseignants travaillent dans le domaine de l’éducation et que M. Brown est un enseignant…", ["M. Brown travaille dans le domaine de l'éducation", "Tout le monde dans l'éducation est un enseignant", "M. Brown ne travaille pas dans l'éducation", "Certains enseignants ne travaillent pas dans l'éducation"], "Tous les enseignants travaillent dans le domaine de l’éducation, M. Brown est enseignant, donc il travaille dans le domaine de l’éducation."],
    "TLR1_19": ["Tous les diamants sont des pierres précieuses. Toutes les pierres précieuses ont de la valeur. Quelle conclusion pouvez-vous tirer ?", "Chaîne : Diamants ⊂ Pierres précieuses ⊂ Objets de valeur.", ["Tous les diamants ont de la valeur", "Toutes les choses de valeur sont des diamants", "Les diamants n'ont pas de valeur", "Certaines pierres précieuses ne valent rien"], "Tous les diamants sont des pierres précieuses, ils ont de la valeur, donc tous les diamants ont de la valeur."],
    "TLR1_20": ["Toutes les journées d'été sont chaudes. Aujourd'hui, c'est un jour d'été. Quelle conclusion pouvez-vous tirer ?", "Si chaque jour d’été est chaud et qu’aujourd’hui c’est un jour d’été…", ["Aujourd'hui il fait chaud", "Toutes les journées chaudes sont l'été", "Il fait froid aujourd'hui", "Les journées d'été ne sont pas toujours chaudes"], "Tous les jours d'été sont chauds, aujourd'hui c'est un jour d'été, donc aujourd'hui il fait chaud."],
    "TLR2_01": ["S'il neige, la température est en dessous de zéro. Neige. Quelle conclusion pouvez-vous tirer ?", "Modus ponens : si P → Q et P est vrai, alors Q est vrai.", ["La température est en dessous de zéro", "La température est au dessus de zéro", "il ne neige pas", "Aucune conclusion ne peut être tirée"], "Modus ponens : P → Q (neige → en dessous de zéro). P est vrai, donc Q est vrai."],
    "TLR2_02": ["Si vous étudiez régulièrement, vos notes s'améliorent. Vos notes ne se sont pas améliorées. Quelle conclusion pouvez-vous tirer ?", "Modus tollens : si P→Q et Q sont faux, alors P est faux.", ["Vous n'avez pas étudié régulièrement", "Vous avez étudié régulièrement", "Notes améliorées", "L'apprentissage n'influence pas les notes"], "Modus tollens : P→Q (apprentissage → meilleures notes). Q est faux, donc P est faux."],
    "TLR2_03": ["Si le téléphone est complètement chargé, il dure toute la journée. Votre téléphone est complètement chargé. Quelle conclusion pouvez-vous tirer ?", "L’antécédent est vrai – le modus ponens s’applique.", ["Le téléphone durera toute la journée", "Le téléphone ne tiendra pas toute la journée", "Le téléphone n'est pas chargé", "Aucune conclusion ne peut être tirée"], "Modus ponens : P→Q (chargé → tenir la journée). P est vrai, donc Q est vrai."],
    "TLR2_04": ["Si l'alarme est activée, elle sonne à 7 heures du matin. L’alarme ne s’est pas déclenchée à 7 heures. Quelle conclusion pouvez-vous en tirer ?", "La conséquence est fausse : elle applique le modus tollens.", ["L'alarme n'a pas été réglée", "L'alarme a été réglée", "L'alarme s'est déclenchée à 7 heures", "L'alarme est cassée"], "Modus tollens : P → Q (alarme réglée → sonnerie à 7h). Q est faux, donc P est faux."],
    "TLR2_05": ["Si vous avez la bonne clé, la serrure s'ouvre. Vous avez la bonne clé. Quelle conclusion pouvez-vous tirer ?", "L’antécédent est rempli — le modus ponens s’applique.", ["La serrure s'ouvre", "La serrure ne s'ouvre pas", "Vous n'avez pas la bonne clé", "La serrure est bloquée"], "Modus ponens : P→Q (bonne clé → ouverture). P est vrai, donc Q est vrai."],
    "TLR2_06": ["Si le courant est allumé, le réfrigérateur fonctionne. Le réfrigérateur ne fonctionne pas. Quelle conclusion pouvez-vous tirer ?", "La conséquence est fausse : elle applique le modus tollens.", ["Le courant n'est pas activé", "Le courant est allumé", "Le frigo fonctionne", "Aucune conclusion ne peut être tirée"], "Modus tollens : P → Q (courant branché → réfrigérateur qui tourne). Q est faux, donc P est faux."],
    "TLR2_07": ["Si vous arrosez les plantes quotidiennement, elles restent vertes. Vous les arrosez quotidiennement. Quelle conclusion pouvez-vous tirer ?", "La condition est remplie : que déduit-on ?", ["Vos plantes restent vertes", "Les plantes se fanent", "Vous ne les arrosez pas", "L'arrosage n'a aucun effet"], "Modus ponens : P→Q (arrosage quotidien → plantes vertes). P est vrai, donc Q est vrai."],
    "TLR2_08": ["Si la voiture a du carburant, le moteur peut démarrer. Le moteur ne démarre pas. Quelle conclusion pouvez-vous tirer ?", "Le résultat ne s’est pas produit : appliquez le modus tollens.", ["La voiture n'a pas de carburant", "La voiture a du carburant", "Le moteur a démarré", "Aucune conclusion ne peut être tirée"], "Modus tollens : P→Q (carburant → démarrage). Q est faux, donc P est faux."],
    "TLR2_09": ["Si vous achetez un billet, vous pouvez monter dans le train. Vous avez acheté un billet. Quelle conclusion pouvez-vous tirer ?", "Vous avez rempli la condition : quelle est la prochaine étape ?", ["Tu peux monter dans le train", "Tu ne peux pas monter dans le train", "Tu n'as pas acheté de billet", "Le train est annulé"], "Modus ponens : P→Q (billet → montées). P est vrai, donc Q est vrai."],
    "TLR2_10": ["Si vous possédez un passeport valide, vous pouvez traverser la frontière. Vous ne pouvez pas traverser la frontière. Quelle conclusion pouvez-vous tirer ?", "Si P → Q et Q sont faux, qu'est-ce que cela signifie pour P ?", ["Vous n'avez pas de passeport valide", "Vous avez un passeport valide", "Tu as traversé la frontière", "Pas besoin de passeport"], "Modus tollens : P→Q (passeport → pass). Q est faux, donc P est faux."],
    "TLR2_11": ["Si un animal est un cheval, il a quatre pattes. Cet animal a quatre pattes. Quelle conclusion pouvez-vous tirer ?", "La vérité du conséquent ne prouve pas l’antécédent. De nombreux animaux ont quatre pattes.", ["On ne peut pas conclure que c'est un cheval", "C'est définitivement un cheval", "Il a deux pattes", "Ce n'est pas un animal"], "Erreur d'affirmation du conséquent : P → Q et Q ne donnent pas P. De nombreux animaux autres que les chevaux ont quatre pattes."],
    "TLR2_12": ["Si quelqu’un est avocat, il a étudié le droit. Sam a étudié le droit. Quelle conclusion pouvez-vous tirer ?", "Ce n’est pas parce que Q est vrai que P est vrai.", ["Nous ne pouvons pas conclure que Sam est avocat", "Sam est définitivement un avocat", "Sam n'a pas étudié le droit", "Tous ceux qui ont étudié le droit sont avocats"], "Énoncé du conséquent : De P → Q (avocat → a étudié le droit) et Q il ne s'ensuit pas que Sam soit avocat."],
    "TLR2_13": ["Si le four est allumé, la cuisine chauffe. La cuisine n'est pas chaleureuse. Quelle conclusion pouvez-vous tirer ?", "La conséquence est fausse : modus tollens.", ["Le four n'est pas allumé", "Le four est allumé", "La cuisine est chaleureuse", "Aucune conclusion ne peut être tirée"], "Modus tollens : P→Q (four → chaud). Q est faux, donc P est faux."],
    "TLR2_14": ["Si vous freinez, la voiture ralentit. Vous freinez. Quelle conclusion pouvez-vous tirer ?", "L’antécédent est vrai : le modus ponens.", ["La voiture ralentit", "La voiture accélère", "Tu n'as pas appuyé sur le frein", "Rien ne se passe"], "Modus ponens : P→Q (freinage → ralentissement). P est vrai, donc Q est vrai."],
    "TLR2_15": ["S'il neige, le ciel est nuageux. Le ciel est couvert. Quelle conclusion pouvez-vous tirer ?", "Un ciel nuageux peut être sans neige : cette affirmation est-elle cohérente ?", ["On ne peut pas conclure qu'il neige", "Bien sûr, il neige", "Le ciel est clair", "Il ne neige jamais quand il fait nuageux"], "Énoncé du conséquent : P → Q et Q n'aboutissent pas à P."],
    "TLR2_16": ["Si la batterie est chargée, la lampe de poche fonctionne. La lampe de poche ne fonctionne pas. Quelle conclusion pouvez-vous tirer ?", "Q est faux – qu’est-ce que cela dit sur P ?", ["La batterie n'est pas chargée", "La batterie est chargée", "La lampe de poche fonctionne", "Aucune conclusion ne peut être tirée"], "Modus tollens : P→Q (chargé → fonctionnel). Q est faux, donc P est faux."],
    "TLR2_17": ["Si vous mettez du sucre dans le thé, le thé devient sucré. Vous mettez du sucre dans votre thé. Quelle conclusion pouvez-vous tirer ?", "La condition est remplie : modus ponens.", ["Le thé devient sucré", "Le thé reste amer", "Tu n'as pas ajouté de sucre", "Le sucre n'a aucun effet"], "Modus ponens : P→Q (sucre → sucré). P est vrai, donc Q est vrai."],
    "TLR2_18": ["Si le routeur Wi-Fi est activé, les appareils peuvent se connecter à Internet. Les appareils ne peuvent pas se connecter. Quelle conclusion pouvez-vous tirer ?", "Q est faux — modus tollens.", ["Le routeur Wi-Fi n'est pas allumé", "Le routeur Wi-Fi est allumé", "Les appareils peuvent se connecter", "Internet n'existe pas"], "Modus tollens : P → Q (on → connecter). Q est faux, donc P est faux."],
    "TLR2_19": ["Si un étudiant s'inscrit au cours, il reçoit le programme. Emma s'est inscrite au cours. Quelle conclusion pouvez-vous tirer ?", "Emma a rempli la condition – quelle est la prochaine étape ?", ["Emma reçoit le programme", "Emma ne comprend pas le programme", "Emma ne s'est pas inscrite", "Le cours n'a pas d'horaire"], "Modus ponens : P→Q (écrit → programme). P est vrai pour Emma, ​​​​donc Q est vrai."],
    "TLR2_20": ["Si c'est dimanche, le magasin est fermé. Ce n'est pas dimanche. Quelle conclusion pouvez-vous tirer ?", "L'antécédent est faux — il ne vous dit pas si Q est vrai (négation de l'antécédent).", ["Nous ne pouvons pas déterminer si le magasin est ouvert ou fermé", "Le magasin est définitivement ouvert", "Le magasin est définitivement fermé", "Ce doit être samedi"], "Nier l'antécédent est une erreur : rien de certain sur Q ne découle de P → Q et du faux P."],
    "TLR3_01": ["Anna est plus grande que Dana. Dana est plus grande que Ben. Ben est plus grand que Carl. Qui est le plus petit ?", "Écrivez la chaîne d'inégalités et trouvez la « base ».", ["Carl", "Ben", "Dana", "Anna"], "Anna > Dana > Ben > Carl. Carl est petit, donc le plus petit."],
    "TLR3_02": ["Félix est plus léger que George. Harry est plus lourd que George. Ivan est plus léger que Félix. Qui est le plus lourd ?", "Ordre : Harry > George > Félix > Ivan.", ["Harry", "George", "Félix", "Ivan"], "Harry > George > Félix > Ivan. Le plus lourd, c'est Harry."],
    "TLR3_03": ["Mia est plus jeune que Nina. Oscar est plus âgé que Nina. Pam est plus jeune que Mia. Qui est le plus âgé ?", "Classement : Oscar > Nina > Mia > Pam.", ["Oscar", "Nina", "Mia", "Pam"], "Oscar > Nina > Mia > Pam. Le plus âgé est Oscar."],
    "TLR3_04": ["Dans une course, Raj termine après Sam. Tina a fini avant Sam. Uma termine après Raj. Qui finit en premier ?", "Premier par ordre d'arrivée = meilleure place. Chaîne : Tina → Sam → Raj → Uma.", ["Tina", "Sam", "Raj", "Ouma"], "Ordre : Tina, Sam, Raj, Uma. La première est Tina."],
    "TLR3_05": ["Victor gagne moins que Wendy. Wendy gagne moins que Xavier. Yara gagne plus que Xavier. Qui gagne le plus ?", "Chaîne : Victor < Wendy < Xavier < Yara.", ["Yara", "Xavier", "Wendy", "Victor"], "Yara > Xavier > Wendy > Victor. Yara gagne le plus."],
    "TLR3_06": ["Eve a un score plus élevé que Frank. Grace a un score inférieur à celui de Frank. Dave a un score plus élevé qu'Eve. Qui a le score le plus bas ?", "Dave > Eve > Frank > Grace. Le plus bas ?", ["Grace", "Frank", "Eve", "Dave"], "Dave > Eve > Frank > Grace. Grace a le score le plus bas."],
    "TLR3_07": ["Lily nage plus vite que Max. Olivia nage plus vite que Lily. Noah nage plus lentement que Max. Qui nage le plus lentement ?", "Par vitesse : Olivia > Lily > Max > Noah.", ["Noah", "Max", "Lily", "Olivia"], "Olivia > Lily > Max > Noah. Le plus lent est Noah."],
    "TLR3_08": ["Quinn est plus petite que Ruth. Steve est plus grand que Tom. Tom est plus grand que Ruth. Qui est le plus grand ?", "Chaîne : Steve > Tom > Ruth > Quinn.", ["Steve", "Tom", "Ruth", "Quinn"], "Steve > Tom > Ruth > Quinn. Le plus grand est Steve."],
    "TLR3_09": ["Amy pèse moins que Brian. Clara pèse plus que Dan. Dan pèse plus que Brian. Qui est la plus légère ?", "Clara > Dan > Brian > Amy.", ["Amy", "Brian", "Dan", "Clara"], "Clara > Dan > Brian > Amy. La plus légère est Amy."],
    "TLR3_10": ["Jake court plus lentement que Kim. Léo court plus vite que Mona. Mona court plus vite que Kim. Qui est le deuxième plus rapide ?", "Léo > Mona > Kim > Jake. Le deuxième ?", ["Mona", "Kim", "Léo", "Jake"], "Léo > Mona > Kim > Jake. Mona est la deuxième en vitesse."],
    "TLR3_11": ["Dans un groupe de 20 étudiants, 12 jouent au tennis et 10 au football. Tout le monde pratique au moins un sport. Combien font les deux ?", "Les deux = A + B − total (lorsque chacun en fait au moins un).", ["2", "4", "8", "10"], "12 + 10 − 20 = 2. Deux élèves pratiquent les deux sports."],
    "TLR3_12": ["Dans un groupe de 25 personnes, 18 aiment le café et 13 aiment le thé. Tout le monde en aime au moins un. Combien de personnes aiment les deux ?", "Les deux = café + thé − total.", ["6", "5", "7", "8"], "18 + 13 − 25 = 6. Six personnes aiment les deux."],
    "TLR3_13": ["Dans une entreprise de 35 salariés, 20 parlent français et 22 allemand. Tout le monde en parle au moins un. Combien parlent tous les deux ?", "Les deux = français + allemand − total.", ["7", "5", "8", "13"], "20 + 22 − 35 = 7. Sept salariés parlent les deux."],
    "TLR3_14": ["Dans un groupe de 40 touristes, 28 ont visité le musée et 18 le parc. Tout le monde a visité au moins un endroit. Combien ont visité les deux ?", "Les deux = musée + parc − total.", ["6", "10", "8", "4"], "28 + 18 − 40 = 6. Six touristes ont visité les deux."],
    "TLR3_15": ["Dans un groupe de 30 lecteurs, 16 lisent de la fiction et 20 lisent de la non-fiction. Tout le monde lit au moins un type. Combien lisent les deux ?", "Les deux = fiction + non-fiction − total.", ["6", "4", "10", "14"], "16 + 20 − 30 = 6. Six lecteurs lisent les deux."],
    "TLR3_16": ["D'affilée, Alice est 3ème en partant de la gauche et 5ème en partant de la droite. Combien de personnes font la queue ?", "Total = position gauche + position droite − 1.", ["7", "8", "6", "9"], "3 + 5 − 1 = 7. Il y a 7 personnes."],
    "TLR3_17": ["D'affilée, Bob est 7ème en partant de la gauche et 4ème en partant de la droite. Combien y a-t-il de personnes ?", "Total = gauche + droite − 1.", ["10", "11", "9", "12"], "7 + 4 − 1 = 10. Il y a 10 personnes."],
    "TLR3_18": ["A la suite, Carol est 5ème depuis l'avant et 9ème depuis l'arrière. Combien de personnes font la queue ?", "Total = recto + verso − 1.", ["13", "14", "12", "15"], "5 + 9 − 1 = 13. Il y a 13 personnes."],
    "TLR3_19": ["A la suite, David est 9ème à l'avant et 3ème à l'arrière. Combien y a-t-il de personnes ?", "Total = recto + verso − 1.", ["11", "12", "10", "13"], "9 + 3 − 1 = 11. Il y a 11 personnes."],
    "TLR3_20": ["D'affilée, Emily est 6ème en partant de la gauche et 6ème en partant de la droite. Combien y a-t-il de personnes ?", "Total = gauche + droite − 1.", ["11", "12", "10", "13"], "6 + 6 − 1 = 11. Il y a 11 personnes."],
    "TLR4_01": ["Cinq personnes sont comparées selon leur poids. E est plus lourd que A, A que B, C que D, D que B, A que C. Classez du plus lourd au plus léger.", "Construisez la chaîne : E > A > C > D > B.", ["E, A, C, D, B", "E, A, D, C, B", "A, E, C, D, B", "E, C, A, D, B"], "E > A > C > D > B. Le plus lourd est E, le plus léger B."],
    "TLR4_02": ["Cinq coureurs terminent une course. Sam termine avant Priya, Priya avant Quinn, Quinn avant Tara, Tara avant Rosa. Qui termine à la 3e place ?", "Ordre d'arrivée : Sam → Priya → Quinn → Tara → Rosa.", ["Quinn", "Priya", "Tara", "Sam"], "Sam, Priya, Quinn, Tara, Rosa. Le troisième est Quinn."],
    "TLR4_03": ["Cinq élèves ont des scores différents. Jack > Fred > Gina > Iris > Hank. Qui a le deuxième score le plus bas (avant-dernière place) ?", "Numéro de bas en haut : Hank, Iris…", ["Iris", "Gina", "Hank", "Fred"], "La deuxième en partant du bas (après Hank) est Iris."],
    "TLR4_04": ["Six athlètes par vitesse : Elena > Diana > Ava > Bella > Chloe > Fiona. Triez du plus rapide au plus lent.", "Construisez étape par étape.", ["Elena, Diana, Ava, Bella, Chloé, Fiona", "Diana, Elena, Ava, Bella, Chloé, Fiona", "Elena, Ava, Diana, Bella, Chloé, Fiona", "Elena, Diana, Bella, Ava, Chloé, Fiona"], "Elena > Diana > Ava > Bella > Chloé > Fiona."],
    "TLR4_05": ["Cinq villes par population : Penny > Liam > Mason > Oliver > Noah. Trier du plus peuplé au moins peuplé.", "Penny > Liam > Mason > Oliver > Noah.", ["Penny, Liam, Mason, Oliver, Noah", "Liam, Penny, Mason, Oliver, Noah", "Penny, Mason, Liam, Oliver, Noah", "Penny, Liam, Oliver, Mason, Noah"], "Penny > Liam > Mason > Oliver > Noah."],
    "TLR4_06": ["Dans une entreprise de 60 salariés, 38 utilisent Windows et 30 Mac. Tout le monde utilise au moins un système. Combien utilisent les deux ?", "Les deux = Windows + Mac − total.", ["8", "10", "12", "6"], "38 + 30 − 60 = 8."],
    "TLR4_07": ["Dans une école de 80 élèves, 55 étudient les mathématiques et 42 les sciences. Tout le monde étudie au moins une matière. Combien étudient les deux ?", "Les deux = mathématiques + sciences − total.", ["17", "15", "20", "23"], "55 + 42 − 80 = 17."],
    "TLR4_08": ["Dans un club de 75 membres, 50 jouent aux échecs et 40 aux dames. Tout le monde joue au moins un jeu. Combien jouent aux deux ?", "Les deux = échecs + dames − total.", ["15", "10", "20", "25"], "50 + 40 − 75 = 15."],
    "TLR4_09": ["Dans une enquête menée auprès de 90 personnes, 60 préfèrent le chocolat et 52 la vanille. Tout le monde aime au moins un goût. Combien de personnes aiment les deux ?", "Les deux = chocolat + vanille − total.", ["22", "18", "30", "12"], "60 + 52 − 90 = 22."],
    "TLR4_10": ["Dans un groupe de 100 électeurs, 72 soutiennent la proposition A et 65 soutiennent la proposition B. Chacun en soutient au moins une. Combien soutiennent les deux ?", "Les deux = A + B − total.", ["37", "35", "40", "28"], "72 + 65 − 100 = 37."],
    "TLR4_11": ["Dans une enquête, 50 personnes : 30 possèdent une voiture, 25 un vélo, 10 les deux. Combien n’en ont pas ?", "Au moins un = voiture + vélo − les deux. Aucun = total − au moins un.", ["5", "10", "15", "0"], "30 + 25 − 10 = 45 en ont au moins un. 50 − 45 = 5 n’en ont pas."],
    "TLR4_12": ["Dans une classe de 45 élèves, 28 ont réussi les mathématiques, 20 les sciences, 8 les deux. Combien ont réussi exactement une matière ?", "Un seul = (mathématiques uniquement) + (sciences uniquement).", ["32", "40", "28", "20"], "Mathématiques uniquement : 28−8=20. Sciences uniquement : 20−8=12. Total 32."],
    "TLR4_13": ["Soixante personnes : 40 jouent de la guitare, 30 du piano ; chacun joue au moins un instrument. Combien ne jouent qu'un seul instrument ?", "Les deux instruments = guitare + piano − 60. Un seul instrument = 60 − ceux qui font les deux.", ["50", "60", "40", "30"], "Les deux = 10. Exactement un = 50."],
    "TLR4_14": ["55 étudiants : 32 en cercle artistique, 28 en musique, 12 dans les deux. Combien ne font partie d’aucun cercle ?", "Au moins un = 32+28−12. Aucun = 55 − ceci.", ["7", "5", "10", "3"], "48 ont au moins un cercle. 55−48=7."],
    "TLR4_15": ["70 personnes : 45 lisent des journaux, 38 des magazines, 20 les deux. Combien ne lisent qu'un seul type de lecture ?", "Exactement un = (journal uniquement) + (magazine uniquement).", ["43", "63", "50", "33"], "25 + 18 = 43."],
    "TLR4_16": ["S'il fait froid, Tom met un imperméable. S'il met un imperméable, il prend un parapluie. Il fait froid. Que prend Tom ?", "Chaîne : froid → imperméable → parapluie. Modus ponens deux fois.", ["Un parapluie", "Un chapeau", "Rien", "L'imperméable seulement"], "Il fait froid → imperméable → parapluie. Donc Tom prend un parapluie."],
    "TLR4_17": ["Si Alice apprend, elle fait une promotion. S'il réussit, il obtient son diplôme. S'il obtient son diplôme, il reçoit une offre d'emploi. Alice apprend. Quel est le résultat final ?", "Chaîne : apprentissage → promotion → diplôme → offre.", ["Alice reçoit une offre d'emploi", "Alice ne réussit que l'examen", "Alice vient tout juste d'obtenir son diplôme", "Aucune conclusion ne peut être tirée"], "Alice parcourt toute la chaîne jusqu'à l'offre d'emploi."],
    "TLR4_18": ["En cas de coupure de courant, l'ordinateur s'éteint. S'il s'arrête, vous perdez le travail non sauvegardé. L'œuvre n'a pas été perdue. Quelle conclusion tirez-vous ?", "Modus tollens en chaîne.", ["Le courant n'est pas tombé", "Le courant a baissé", "L'ordinateur s'est arrêté", "Le travail est perdu"], "Travail non perdu → l'ordinateur ne s'est pas éteint → l'alimentation n'a pas été coupée."],
    "TLR4_19": ["S'il pleut, le match est annulé. En cas d'annulation, les billets sont restitués. Les billets n'ont pas été restitués. Quelle conclusion ?", "Non rendu → le match n'est pas annulé → il n'a pas plu.", ["il n'a pas plu", "Il a plu", "Le match a été annulé", "Les billets ont été rendus"], "Double modus tollens : il ne pleut pas."],
    "TLR4_20": ["Si vous mangez trop de sucre, vous prendrez du poids. Si vous prenez du poids, vous avez besoin d'exercice. Si vous en avez besoin, vous rejoignez la salle de sport. Vous n'êtes pas inscrit à la salle de sport. Quelle conclusion ?", "Modus tollens en chaîne.", ["Vous n'avez pas mangé trop de sucre", "Vous avez mangé trop de sucre", "Vous avez pris du poids", "Vous vous êtes inscrit à la salle de sport"], "Pas de salle de sport → pas de besoin d'exercice → pas de prise de poids → pas d'excès de sucre."],
    "TLR5_01": ["Trois personnes : A, B, C. Une seule dit la vérité. A dit : « B et C mentent tous les deux ». B dit : « A ment ». C dit : « A dit la vérité ». Qui dit la vérité ?", "Teste chaque personne comme seule personne sincère.", ["B", "A", "C", "Aucun"], "Si B dit la vérité, alors A et C mentent, et la condition « une seule vérité » est respectée. Les autres cas créent une contradiction."],
    "TLR5_02": ["Trois personnes : D, E, F. Une seule dit la vérité. D dit : « E ment ». E dit : « F ment ». F dit : « D et E mentent tous les deux ». Qui dit la vérité ?", "Teste chaque cas comme unique vérité.", ["E", "D", "F", "Aucun"], "Si E dit la vérité, alors F ment, et la phrase de D est fausse. C’est le seul cas cohérent : E."],
    "TLR5_03": ["G, H, I — suspects. Un seul coupable. Le coupable ment toujours ; les innocents disent la vérité. G : « H est coupable ». H : « Je ne suis pas coupable ». I : « G est coupable ». Qui est coupable ?", "Testez chaque hypothèse.", ["G", "H", "I", "On ne peut pas déterminer"], "Si G est coupable : G ment, donc H est innocent ; H dit la vérité ; I dit la vérité (G coupable). Cohérent avec un seul coupable. Les autres cas mènent à des contradictions."],
    "TLR5_04": ["J, K, L. Une seule personne dit la vérité. J: \"Je dis la vérité\". K: «J dit la vérité». L : \"Je mens.\" Qui dit la vérité ?", "Si J était honnête, K serait également honnête – impossible.", ["L", "J", "K", "Aucun"], "L honnête → J menteur → K menteur ✓. Seul L fonctionne."],
    "TLR5_05": ["M, N, O. Une seule personne dit la vérité. M: «N et O disent tous deux la vérité». N : « Je mens ». O : \"Ça ne me dérange pas\". Qui dit la vérité ?", "Si M était honnête, N et O seraient tous deux honnêtes, ce qui contredit « exactement un ».", ["N", "M", "O", "Aucun"], "N honnête → M menteur ; La déclaration de M est fausse → pas les deux N,O honnête → O ment ✓."],
    "TLR5_06": ["Dans trois jours, ce sera mercredi. quel jour est aujourd'hui", "Compte à rebours de trois jours à partir de mercredi.", ["dimanche", "lundi", "samedi", "mardi"], "Mercredi −3 jours = dimanche."],
    "TLR5_07": ["Hier, c'était vendredi. Quel jour sera-ce après-demain ?", "Découvrez-le aujourd'hui, puis +2 jours.", ["lundi", "dimanche", "mardi", "samedi"], "Hier vendredi → aujourd'hui samedi → après-demain lundi."],
    "TLR5_08": ["Il y a deux jours, c'était lundi. Quel jour sera-ce dans trois jours ?", "Découvrez « aujourd'hui » à partir de « il y a deux jours », puis +3.", ["samedi", "vendredi", "dimanche", "jeudi"], "Il y a deux jours = lundi → aujourd'hui = mercredi → dans trois jours = samedi."],
    "TLR5_09": ["Avant-hier, c'était jeudi. Quel jour sera-t-il demain ?", "Avant-hier = il y a deux jours.", ["dimanche", "samedi", "lundi", "vendredi"], "Avant-hier jeudi → hier vendredi → aujourd'hui samedi → demain dimanche."],
    "TLR5_10": ["Dans quatre jours, ce sera mardi. quel jour était hier", "Aujourd'hui = mardi − 4 jours ; hier = aujourd'hui − 1.", ["jeudi", "vendredi", "mercredi", "samedi"], "Aujourd'hui = vendredi, hier = jeudi."],
    "TLR5_11": ["Six élèves sont classés : Fay > Diana > Abby > Brian > Carl > Elena. Qui est la 3e ?", "Compte depuis le début : 1 Fay, 2 Diana, 3 ...", ["Abby", "Diana", "Brian", "Fay"], "La 3e est Abby."],
    "TLR5_12": ["Cinq pots : 5>1>2>4>3 en poids. Lequel est au milieu (3ème place) ?", "Chaîne complète 5>1>2>4>3.", ["Pot 2", "Pot 1", "Pot 4", "Pot 3"], "Le troisième dans l’ordre est le pot 2."],
    "TLR5_13": ["Sept personnes par âge : T>U>V>W>X>Y>Z. Qui a le quatrième âge ?", "Numéro position 4 dans la chaîne.", ["W", "V", "X", "U"], "Le quatrième est W."],
    "TLR5_14": ["Cinq villes : E>A>B>D>C par population. Quelle est la moins peuplée ?", "C est à la queue de la chaîne.", ["Ville C", "Ville D", "Ville B", "Ville A"], "Le plus petit est C."],
    "TLR5_15": ["Six cartes par pages : T>P>Q>U>R>S. Lequel a l'avant-dernière (avant-dernière) page ?", "En bas : S minimal, puis R.", ["Livre R", "Livre S", "Le livre U", "Le livre Q"], "Le deuxième en partant du bas est R."],
    "TLR5_16": ["Trois boîtes : « Pommes », « Oranges », « Mélange ». Toutes les étiquettes sont fausses. Sortez une pomme de la boîte « Mélange ». Qu'y a-t-il réellement dans la boîte intitulée « Pommes » ?", "« Mélange » est faux — la boîte est homogène ; tu as sorti une pomme → voilà les pommes.", ["Oranges", "Pommes", "Mélange", "On ne peut pas déterminer"], "La boite \"Mix\" contient uniquement des pommes. «Orange» n'a pas d'oranges → mélange. \"Apple\" a des oranges."],
    "TLR5_17": ["Alice, Bob, Carol travaillent à des jours différents : lundi, mardi, mercredi. Alice ne travaille pas le lundi. Bob ne travaille pas le mardi ni le mercredi. Carol ne travaille pas le mercredi. Quel jour Carol travaille-t-elle ?", "Cela commence avec Bob : il a le seul jour possible.", ["mardi", "lundi", "mercredi", "On ne peut pas déterminer"], "Bob uniquement le lundi → Alice le mardi ou le mercredi → Carol pas le mercredi → Carol le mardi."],
    "TLR5_18": ["Si P est vrai, Q est vrai. Si Q est vrai, R est faux. Si R est faux, S est vrai. P est vrai. Est-ce vrai ou faux ?", "Parcourez la chaîne P→Q→¬R→S.", ["C'est vrai", "C'est faux", "S est inconnu", "S dépend de R"], "P → Q → R faux → S vrai."],
    "TLR5_19": ["Cinq amis : Alex > Drew > Blake > Casey > Ellie par âge. Qui est au milieu (troisième âge) ?", "Le troisième sur cinq.", ["Blake", "Drew", "Casey", "Alex"], "Le troisième est Blake."],
    "TLR5_20": ["Dans le classement V,W,X,Y,Z : V avant W ; X immédiatement après Y ; Z à la 3ème place ; W à la 5ème place ; Y avant Z. Quelle place occupe V ?", "Z=3, W=5 ; Y avant Z ; X après Y.", ["4ème place", "1ère place", "2ème place", "3ème place"], "Y=1, X=2, Z=3, V=4, W=5."],
    "TSR1_01": ["Combien de côtés a un pentagone ?", "Le préfixe « penta- » fait référence à un nombre spécifique.", ["5", "4", "6", "7"], "\"Pentagone\" vient du grec pour cinq. Un pentagone a exactement 5 côtés."],
    "TSR1_02": ["Combien de côtés a un hexagone ?", "Le préfixe « hexa- » indique un nombre : pensez à six (comme six côtés).", ["6", "5", "8", "7"], "\"Hexagone\" vient du grec pour six. Un hexagone a 6 côtés."],
    "TSR1_03": ["Combien de côtés a un octogone ?", "Pensez à la pieuvre : combien de bras a-t-elle ?", ["8", "6", "10", "7"], "Le préfixe « octa- » signifie huit, comme dans poulpe. Un octogone a 8 côtés."],
    "TSR1_04": ["Combien d'angles a un triangle ?", "Le préfixe « tri- » vous donne directement la réponse.", ["3", "4", "2", "1"], "Un triangle a 3 angles : un à chaque sommet où deux côtés se rencontrent."],
    "TSR1_05": ["Combien d’angles a un pentagone ?", "Chaque côté rencontre le suivant sous un angle. Comptez les côtés.", ["5", "4", "6", "3"], "Tout polygone a autant d'angles que de côtés. Un pentagone a 5 côtés et 5 angles."],
    "TSR1_06": ["Combien de faces possède une boîte rectangulaire (prisme rectangulaire) ?", "Pensez vers le haut, le bas, l'avant, l'arrière, la gauche et la droite.", ["6", "4", "8", "5"], "Un prisme rectangulaire a 6 faces : haut, bas, avant, arrière, gauche, droite."],
    "TSR1_07": ["Combien de sommets (coins) possède un triangle ?", "Un sommet est l'endroit où deux côtés se rencontrent. Comptez les coins.", ["3", "4", "2", "6"], "Un triangle a 3 sommets, un à chaque coin."],
    "TSR1_08": ["Quelle forme 2D a exactement 3 côtés et 3 angles ?", "C'est l'un des polygones les plus simples.", ["Triangle", "Carré", "Pentagone", "Cercle"], "Un triangle est un polygone ayant 3 côtés et 3 angles."],
    "TSR1_09": ["Si vous pliez une feuille de papier en deux, combien de couches de papier avez-vous ?", "Avant de plier, vous avez 1 couche. Doublez le nombre.", ["2", "1", "3", "4"], "Chaque pli en deux double les couches. En partant de 1, un pli donne 2 couches."],
    "TSR1_10": ["Quelle est la forme de chaque face d’un cube standard ?", "Toutes les faces du cube sont identiques. Quelle forme régulière a 4 côtés égaux et 4 angles droits ?", ["Carré", "Rectangulaire", "Triangle", "Cercle"], "Le cube a 6 faces et chacune est un carré."],
    "TSR1_11": ["Quel corps 3D a le même aspect, quelle que soit la façon dont vous le coupez au centre ?", "Il n’a ni arêtes, ni sommets, il est parfaitement rond.", ["Sphère", "Cylindre", "Cône", "Cube"], "La sphère est parfaitement symétrique. Toute coupe passant par le centre donne un cercle identique."],
    "TSR1_12": ["Combien de côtés droits a un cercle ?", "Le cercle est courbé partout. Y a-t-il des côtés droits ?", ["0", "1", "2", "Infini"], "Le cercle n'a pas de côtés droits : c'est une courbe continue sans coins ni segments droits."],
    "TSR1_13": ["Combien de côtés a un triangle ?", "Le nom dit : « tri » signifie trois.", ["3", "2", "4", "5"], "Un triangle est un polygone ayant exactement 3 côtés."],
    "TSR1_14": ["Combien de côtés a un carré ?", "Pensez à une fenêtre ou à un damier.", ["4", "3", "5", "6"], "Un carré a 4 côtés égaux et 4 angles droits."],
    "TSR1_15": ["Combien de sommets (coins) possède un carré ?", "Comptez les points où deux côtés se rencontrent.", ["4", "3", "5", "6"], "Le carré a 4 sommets, un à chaque coin."],
    "TSR1_16": ["Combien de sommets possède un hexagone ?", "Un polygone a toujours autant de sommets que de côtés.", ["6", "5", "8", "4"], "L'hexagone a 6 côtés, donc 6 sommets."],
    "TSR1_17": ["Si vous pliez une feuille en deux deux fois, combien de couches obtenez-vous ?", "Chaque pli double le nombre actuel de couches.", ["4", "2", "3", "8"], "Premier pli : 1 → 2 couches. Deuxièmement : 2 → 4 couches."],
    "TSR1_18": ["Quelle forme a 4 côtés, tous angles à 90° et côtés opposés parallèles ?", "C’est la forme la plus courante pour les portes, les paravents et les livres.", ["Rectangulaire", "Trapèze", "Losange", "Parallélogramme"], "Le rectangle a 4 côtés, parallèles opposés, tous angles intérieurs 90°."],
    "TSR1_19": ["Combien de coins a un rectangle ?", "Un coin est l'endroit où deux côtés se rencontrent selon un angle.", ["4", "2", "3", "5"], "Le rectangle a 4 coins (sommets), un à chaque angle droit."],
    "TSR1_20": ["Quelle forme 2D a tous les points du contour à la même distance du centre ?", "Pensez à une pièce de monnaie vue d'en haut ou à une pizza.", ["Cercle", "Ellipses", "Carré", "Ovale"], "Un cercle est l'ensemble des points équidistants du centre. Cette distance constante est le rayon."],
    "TSR2_01": ["Combien de côtés a un prisme rectangulaire (boîte) ?", "Comptez les bords supérieurs et inférieurs des faces et les bords verticaux qui les relient.", ["12", "8", "10", "6"], "Prisme rectangulaire : 4 bords supérieurs + 4 inférieurs + 4 verticaux = 12 bords."],
    "TSR2_02": ["Combien de sommets possède un prisme rectangulaire ?", "Comptez séparément les coins supérieurs et inférieurs de la face.", ["8", "6", "10", "12"], "4 sommets en haut + 4 sommets en bas = 8 sommets."],
    "TSR2_03": ["Combien de faces possède un prisme pentagonal ?", "Un prisme de base à n côtés a n faces rectangulaires latérales plus 2 bases.", ["7", "5", "10", "6"], "2 bases pentagonales + 5 faces rectangulaires latérales = 7 faces."],
    "TSR2_04": ["Combien d’arêtes possède un prisme triangulaire ?", "Comptez les bords de chaque base triangulaire, puis les bords qui les relient.", ["9", "6", "8", "12"], "3 bords vers le haut + 3 vers le bas + 3 verticaux = 9 bords."],
    "TSR2_05": ["Combien de sommets possède un prisme triangulaire ?", "Chaque base triangulaire apporte ses propres sommets.", ["6", "5", "8", "9"], "3 sommets sur chaque base : 3 + 3 = 6 sommets."],
    "TSR2_06": ["Si 4 cubes identiques sont en ligne droite, chacun partageant une face avec le suivant, combien de faces sont visibles au total (y compris la face du bas) ?", "Cela commence par 4×6 faces, puis soustrait les faces cachées à chaque jointure.", ["18", "20", "16", "24"], "4 cubes : 24 faces. 3 jointures × 2 faces cachées = 6. 24 − 6 = 18 visibles."],
    "TSR2_07": ["Combien de faces possède un prisme hexagonal ?", "Le prisme de base n-gon a n + 2 faces.", ["8", "6", "12", "10"], "2 bases hexagonales + 6 faces rectangulaires = 8 faces."],
    "TSR2_08": ["Combien d’arêtes possède un prisme pentagonal ?", "Pour un prisme à base à n côtés : arêtes totales = 3n.", ["15", "10", "12", "20"], "5 vers le haut + 5 vers le bas + 5 verticaux = 3 × 5 = 15 bords."],
    "TSR2_09": ["Combien de sommets possède un prisme pentagonal ?", "Le prisme duplique les sommets du polygone de base.", ["10", "12", "8", "15"], "5 sommets par base × 2 bases = 10 sommets."],
    "TSR2_10": ["Combien d’arêtes possède une pyramide à base carrée ?", "Comptez les bords de la base, puis les bords depuis les coins de la base jusqu'au sommet.", ["8", "5", "6", "10"], "4 bords à la base + 4 bords latéraux vers le haut = 8 bords."],
    "TSR2_11": ["Combien de sommets possède une pyramide à base carrée ?", "N'oubliez pas le sommet au-dessus de la base !", ["5", "4", "6", "8"], "4 sommets à la base + 1 sommet = 5 sommets."],
    "TSR2_12": ["Combien de faces possède une pyramide à base carrée ?", "Comptez la base et chaque face latérale triangulaire.", ["5", "4", "6", "8"], "1 base carrée + 4 faces triangulaires = 5 faces."],
    "TSR2_13": ["Combien d’arêtes possède un prisme hexagonal ?", "Formule : bords = 3 × le nombre de côtés de la base.", ["18", "12", "24", "15"], "6 + 6 + 6 = 3 × 6 = 18 arêtes."],
    "TSR2_14": ["Combien de sommets possède un prisme hexagonal ?", "Chaque base hexagonale comporte 6 coins.", ["12", "8", "6", "18"], "6 sommets par base × 2 bases = 12 sommets."],
    "TSR2_15": ["Si 5 cubes identiques sont alignés, partageant des faces, combien de faces sont visibles au total (y compris celle du bas) ?", "5 cubes = 30 faces. Combien d’articulations et combien de visages chacune cache-t-elle ?", ["22", "20", "24", "26"], "30 faces − 4 joints × 2 = 30 − 8 = 22 visibles."],
    "TSR2_16": ["Combien de faces possède un prisme octogonal ?", "Formule du prisme : n + 2 faces pour une base à n côtés.", ["10", "8", "12", "16"], "2 bases octogonales + 8 faces latérales rectangulaires = 10 faces."],
    "TSR2_17": ["Combien d’arêtes possède un prisme octogonal ?", "Formule : 3n arêtes pour une base à n côtés.", ["24", "16", "20", "32"], "3 × 8 = 24 arêtes."],
    "TSR2_18": ["Combien de sommets possède une pyramide triangulaire (tétraèdre) ?", "Base triangulaire et un point au dessus.", ["4", "3", "5", "6"], "Tétraèdre : 3 sommets à la base + 1 sommet = 4 sommets."],
    "TSR2_19": ["Formule d'Euler : V − E + F = 2 pour les polyèdres convexes (E = nombre d'arêtes). Si un polyèdre a 6 sommets et 12 arêtes, combien de faces a-t-il ?", "Réorganiser : F = 2 − V + E.", ["8", "6", "10", "7"], "F = 2 − 6 + 12 = 8 faces (ex : cube régulier ou octaèdre)."],
    "TSR2_20": ["Combien de diagonales a un carré ?", "Une diagonale relie deux sommets non adjacents. Le carré a 4 sommets.", ["2", "4", "1", "3"], "Le carré a 2 diagonales, chacune reliant des coins opposés."],
    "TSR3_01": ["Un cube 3×3×3 est peint sur toutes ses faces, puis découpé en 27 petits cubes. Combien de cubes ont au moins une face peinte ?", "Seul le cube exactement au centre de la grille 3×3×3 n’a pas de peinture. Combien de cubes ne sont pas au centre ?", ["26", "24", "20", "27"], "Un seul cube (le centre) a 0 faces peintes. Donc 27 − 1 = 26 ont au moins un visage peint."],
    "TSR3_02": ["Un cube 3×3×3 est peint sur toutes ses faces et découpé en 27 petits cubes. Combien de faces d’unités peintes les 27 cubes ont-ils au total ?", "Chacune des 6 faces du grand cube est une grille 3×3, donc 9 faces unitaires peintes par face.", ["54", "48", "36", "27"], "6 faces × 9 = 54 faces unitaires peintes."],
    "TSR3_03": ["Le cube 3×3×3 peint est découpé en 27 petits cubes. Combien de cubes ont au plus une face peinte ?", "Comptez les cubes avec 0 faces peintes et exactement 1, puis additionnez.", ["7", "6", "8", "12"], "1 cube à 0 faces (le centre) + 6 cubes à exactement 1 (les centres des faces). Total : 1 + 6 = 7."],
    "TSR3_04": ["Le cube 3×3×3 peint est découpé en 27 petits cubes. Combien de cubes ont au moins 2 faces peintes ?", "Ce sont les cubes de coin (3 côtés) et ceux du bord (2 côtés).", ["20", "12", "8", "18"], "8 coins (3 peints) + 12 bords × 1 cube central à 2 faces = 20 cubes avec 2 faces peintes ou plus."],
    "TSR3_05": ["Si vous coupez un cube avec un plan parallèle à l’une des faces, quelle forme a la section ?", "Couper parallèlement à une face carrée donne une forme conforme à cette face.", ["Carré", "Rectangulaire", "Triangle", "Hexagone"], "Le plan parallèle à une face coupe quatre arêtes égales et donne un carré."],
    "TSR3_06": ["Si vous coupez un cylindre avec un plan perpendiculaire à son axe, quelle forme aura la section ?", "L'axe passe par les centres des deux bases circulaires.", ["Cercle", "Ellipses", "Rectangulaire", "Ovale"], "La coupe perpendiculaire à l'axe est parallèle aux bases — vous obtenez un cercle."],
    "TSR3_07": ["Si vous coupez un cône avec un plan parallèle à la base circulaire, quelle forme obtenez-vous ?", "La base du cône est un cercle. La découpe parallèle donne une forme similaire.", ["Cercle", "Ellipses", "Triangle", "Parabole"], "Le plan parallèle à la base coupe le cône en un cercle (plus petit que la base)."],
    "TSR3_08": ["Combien de sommets possède une sphère ?", "Le sommet est l’endroit où les bords se rejoignent. La sphère a-t-elle des bords ?", ["0", "1", "2", "Infini"], "La sphère est une surface lisse, sans bords, donc sans pics."],
    "TSR3_09": ["Combien d’arêtes possède une sphère ?", "Le bord est le segment où se rencontrent deux faces planes.", ["0", "1", "2", "Infini"], "La sphère n’a pas de faces planes, elle n’a donc pas d’arêtes."],
    "TSR3_10": ["Combien de faces a une pyramide hexagonale ?", "La pyramide a 1 base plus des faces triangulaires latérales – une de chaque côté de la base.", ["7", "6", "8", "12"], "1 base hexagonale + 6 faces triangulaires latérales = 7 faces."],
    "TSR3_11": ["Combien d’arêtes possède une pyramide hexagonale ?", "Comptez les bords de la base et les bords de chaque sommet de la base jusqu'au sommet de la pyramide.", ["12", "6", "8", "18"], "6 bords à la base + 6 bords latéraux vers le haut = 12 bords."],
    "TSR3_12": ["Combien de sommets possède une pyramide hexagonale ?", "Comptez les sommets de la base et le sommet supérieur unique.", ["7", "6", "8", "12"], "6 sommets à la base + 1 sommet = 7 sommets. (Vérification d'Euler : 7 − 12 + 7 = 2 ✓)"],
    "TSR3_13": ["Si vous coupez un cube du milieu d’une arête jusqu’au milieu de l’arête parallèle opposée, quelle forme la section peut-elle avoir ?", "La coupe entre deux arêtes parallèles donne un quadrilatère plan.", ["Rectangulaire", "Triangle", "Pentagone", "Cercle"], "Le plan passant par les milieux de deux arêtes parallèles opposées donne une section rectangulaire."],
    "TSR3_14": ["Combien de faces possède une pyramide à base pentagonale ?", "1 socle + faces latérales (une par côté du socle).", ["6", "5", "7", "10"], "1 base pentagonale + 5 faces triangulaires = 6 faces."],
    "TSR3_15": ["Combien d’arêtes possède une pyramide à base pentagonale ?", "Pour pyramide à base à n côtés : 2n arêtes.", ["10", "5", "8", "15"], "5 bords à la base + 5 côtés = 10 bords."],
    "TSR3_16": ["Combien de sommets possède une pyramide à base pentagonale ?", "Les sommets de la base plus le sommet supérieur.", ["6", "5", "7", "10"], "5 sommets à la base + 1 sommet = 6 sommets. (Vérifiez : 6 − 10 + 6 = 2 ✓)"],
    "TSR3_17": ["En utilisant la formule d'Euler (V − E + F = 2), si un polyèdre a 5 sommets et 8 arêtes, combien de faces a-t-il ?", "Résolvez F : F = 2 − V + E.", ["5", "4", "6", "7"], "F = 2 − 5 + 8 = 5 (ex : pyramide à base carrée : 5 sommets, 8 arêtes, 5 faces)."],
    "TSR3_18": ["Combien de diagonales possède un hexagone régulier ?", "Pour un polygone à n côtés : n(n − 3) / 2.", ["9", "6", "12", "3"], "Diagonales = 6 × (6 − 3) / 2 = 9."],
    "TSR3_19": ["Dans un cube peint 3×3×3 découpé en 27 cubes, combien de faces peintes au total ont seuls les 8 cubes de coin ?", "Chaque cube de coin a exactement 3 faces peintes.", ["24", "8", "12", "18"], "8 coins × 3 faces = 24 faces peintes aux coins."],
    "TSR3_20": ["Combien de diagonales possède un pentagone régulier ?", "Utilisez n(n − 3) / 2 avec n = 5.", ["5", "4", "6", "3"], "Diagonales = 5 × (5 − 3) / 2 = 5."],
    "TSR4_01": ["Un cube 4×4×4 est peint sur toutes ses faces, puis découpé en 64 petits cubes. Combien de cubes ont au moins une face peinte ?", "L'intérieur non peint forme un cube plus petit de côté (4 − 2) = 2.", ["56", "48", "52", "60"], "Cubes avec 0 peinture à l'intérieur = 2³ = 8. Avec au moins 1 face peinte : 64 − 8 = 56."],
    "TSR4_02": ["Le cube 4×4×4 peint est découpé en 64 petits cubes. Combien de cubes ont au moins 2 faces peintes ?", "Cubes d'angle (3 faces) et cubes de bord (2 faces). Collectionnez-les.", ["32", "24", "36", "28"], "Coins : 8. Bords : 12 × 2 cubes moyens = 24. Total : 8 + 24 = 32."],
    "TSR4_03": ["Le cube 4×4×4 peint est découpé en 64 petits cubes. Combien de faces d’unités peintes tous les cubes ont-ils au total ?", "Chacune des 6 faces du grand cube est une grille 4×4.", ["96", "64", "72", "108"], "6 × 16 = 96. (Vérifiez : 8 × 3 + 24 × 2 + 24 × 1 = 96 ✓)"],
    "TSR4_04": ["Le cube 4×4×4 peint est découpé en 64 petits cubes. Combien de cubes ont au plus une face peinte ?", "Ajoutez les cubes avec 0 faces peintes et exactement 1.", ["32", "24", "28", "36"], "0 face peinte : 8 (intérieur 2×2×2). 1 face peinte : 24 (centres des faces). Total : 32."],
    "TSR4_05": ["Si vous supprimez un cube de coin d'un cube 3×3×3, combien de faces des cubes unités sont visibles sur le solide restant (y compris le fond) ?", "En supprimant le coin vous perdez 3 faces extérieures mais révélez 3 faces intérieures précédemment cachées.", ["54", "51", "57", "48"], "Superficie initiale : 6 × 9 = 54. Au coin : −3 extérieur + 3 nouvellement visibles intérieur = 0 net. La surface totale reste 54."],
    "TSR4_06": ["Combien de diagonales possède un octogone régulier ?", "Formule n(n − 3) / 2 avec n = 8.", ["20", "16", "24", "8"], "Diagonales = 8 × 5 / 2 = 20."],
    "TSR4_07": ["Combien de diagonales spatiales possède un cube ? (La diagonale spatiale traverse l’intérieur d’un sommet au sommet opposé.)", "Le cube a 8 sommets. Chaque diagonale spatiale relie un sommet à son opposé.", ["4", "6", "8", "12"], "Le cube a 4 diagonales spatiales, chacune passant par le centre."],
    "TSR4_08": ["Combien de diagonales de faces un cube possède-t-il au total ?", "Chaque visage est carré. Combien de diagonales le carré a-t-il ? Multipliez par 6.", ["12", "6", "8", "24"], "6 faces × 2 diagonales = 12 diagonales en faces."],
    "TSR4_09": ["Combien de faces possède un octaèdre régulier (deux pyramides carrées collées ensemble à la base) ?", "Chaque pyramide apporte 4 faces triangulaires. La base carrée commune se trouve à l’intérieur.", ["8", "6", "12", "20"], "L'octaèdre régulier possède 8 faces triangulaires équilatérales."],
    "TSR4_10": ["Combien d’arêtes possède un octaèdre régulier ?", "Utilisez la formule d'Euler si vous connaissez V = 6 et F = 8.", ["12", "8", "6", "24"], "E = V + F − 2 = 6 + 8 − 2 = 12 arêtes."],
    "TSR4_11": ["Combien de sommets possède un octaèdre régulier ?", "Pensez à deux pyramides reliées à la base. Comptez les sommets distincts.", ["6", "8", "12", "4"], "4 sommets autour de l'équateur carré + 1 sommet vers le haut + 1 vers le bas = 6."],
    "TSR4_12": ["Si 8 cubes unitaires forment un cube 2×2×2, combien de faces des cubes unitaires sont visibles à l’extérieur (y compris le bas) ?", "Le résultat est un cube de côté 2. Superficie totale en faces unitaires ?", ["24", "28", "32", "20"], "6 × (2 × 2) = 24 faces unitaires."],
    "TSR4_13": ["Un dodécaèdre régulier possède 12 faces pentagonales et 30 arêtes. Avec la formule d'Euler, combien de sommets a-t-il ?", "V = 2 + E - F.", ["20", "12", "24", "30"], "V = 2 + 30 − 12 = 20 sommets."],
    "TSR4_14": ["Un icosaèdre régulier possède 20 faces triangulaires et 12 sommets. Combien de bords a-t-il ?", "E = V + F − 2.", ["30", "20", "24", "36"], "E = 12 + 20 − 2 = 30 arêtes."],
    "TSR4_15": ["Dans un cube peint 4×4×4, combien de faces peintes les 8 cubes de coin ont-ils au total ?", "Tout cube de coin a exactement 3 faces peintes, quelle que soit la taille du grand cube.", ["24", "8", "12", "32"], "8 × 3 = 24."],
    "TSR4_16": ["Dans le même cube 4×4×4, combien de faces peintes les cubes de bord (ceux avec exactement 2 faces peintes) ont-ils ?", "Combien y a-t-il de cubes sur les bords, puis multipliez par 2.", ["48", "24", "36", "60"], "24 cubes sur arêtes (12 arêtes × 2), chacun avec 2 faces peintes : 24 × 2 = 48."],
    "TSR4_17": ["Si on coupe un cube avec un plan au moyen de trois arêtes partant du même sommet, quelle forme a la section ?", "Les trois points milieux sont à égale distance du sommet. Quel triangle a tous ses côtés égaux ?", ["Triangle équilatéral", "Carré", "Triangle rectangle", "Hexagone régulier"], "Le plan coupe les trois bords de manière égale : vous obtenez un triangle équilatéral."],
    "TSR4_18": ["Combien de diagonales possède un décagone régulier (10 côtés) ?", "Formule : n(n − 3) / 2.", ["35", "30", "40", "25"], "10 × 7/2 = 35."],
    "TSR4_19": ["Un prisme a exactement 10 sommets. Quelle est la forme de la base ?", "Le prisme de base à n côtés a 2n sommets.", ["Pentagone", "Carré", "Hexagone", "Triangle"], "2n = 10 → n = 5. La base est un pentagone."],
    "TSR4_20": ["Une pyramide a exactement 7 faces. Quelle est la forme de la base ?", "La pyramide de base à n côtés a n + 1 faces.", ["Hexagone", "Pentagone", "Heptagone", "Octogone"], "n + 1 = 7 → n = 6. La base est un hexagone."],
    "TSR5_01": ["Un cube 5×5×5 est peint sur toutes ses faces, puis découpé en 125 petits cubes. Combien de cubes ont exactement 2 faces peintes ?", "Les cubes sur les bords (et non les coins) ont 2 faces peintes. Formule : 12(n − 2).", ["36", "24", "48", "30"], "12 × (5 − 2) = 36."],
    "TSR5_02": ["Le cube 5×5×5 peint est découpé en 125 petits cubes. Combien de cubes ont exactement 3 faces peintes ?", "Seuls les cubes de coin ont 3 faces peintes. Combien de coins possède un cube ?", ["8", "12", "20", "6"], "Tout cube a 8 coins. Donc 8 cubes avec exactement 3 faces peintes."],
    "TSR5_03": ["Le cube 5×5×5 peint est découpé en 125 petits cubes. Combien de cubes ont au moins une face peinte ?", "Soustrayez les cubes à l'intérieur complètement non peints : (n − 2)³.", ["98", "96", "100", "90"], "À l'intérieur = 3³ = 27. 125 − 27 = 98."],
    "TSR5_04": ["Le cube 5×5×5 peint est découpé en 125 petits cubes. Combien de faces d’unités peintes tous les cubes ont-ils au total ?", "Chacune des 6 faces du grand cube est une grille 5×5.", ["150", "125", "144", "162"], "6 × 25 = 150."],
    "TSR5_05": ["Un cube peint 6×6×6 est découpé en 216 petits cubes. Combien ont exactement 2 faces peintes ?", "12(n − 2) avec n = 6.", ["48", "36", "60", "24"], "12 × 4 = 48."],
    "TSR5_06": ["Le cube peint 6×6×6 est découpé en 216 petits cubes. Combien ont exactement 1 visage peint ?", "6(n − 2)² avec n = 6.", ["96", "72", "108", "84"], "6 × 16 = 96."],
    "TSR5_07": ["Le cube peint 6×6×6 est découpé en 216 petits cubes. Combien n’ont aucune face peinte ?", "Bloc intérieur : (n − 2)³.", ["64", "48", "36", "27"], "(6 − 2)³ = 64."],
    "TSR5_08": ["Le cube peint 6×6×6 est découpé en 216 petits cubes. Combien ont exactement 3 faces peintes ?", "Les coins sont toujours au nombre de 8, quelle que soit leur taille.", ["8", "12", "6", "24"], "8 cubes avec 3 faces peintes. (Vérifiez : 8+48+96+64=216 ✓)"],
    "TSR5_09": ["Le cube peint 6×6×6 est découpé en 216 petits cubes. Combien de faces d’unités peintes ont-ils au total ?", "Chaque face du grand cube est une grille 6×6.", ["216", "200", "192", "240"], "6 × 36 = 216."],
    "TSR5_10": ["Dans un cube peint 10×10×10 découpé en 1000 cubes, combien y a-t-il exactement de 2 faces peintes ?", "12(n − 2) pour les cubes sur les bords.", ["96", "120", "80", "108"], "12 × 8 = 96."],
    "TSR5_11": ["Dans le même cube 10×10×10, combien de petits cubes ont exactement 1 face peinte ?", "6(n − 2)² pour les centres des faces.", ["384", "360", "400", "480"], "6 × 64 = 384."],
    "TSR5_12": ["Combien de petits cubes n’ont aucune face peinte ?", "L'intérieur est un cube de côté (n − 2).", ["512", "480", "500", "343"], "(10 − 2)³ = 512."],
    "TSR5_13": ["Laquelle de ces formes PEUT être la section d’un cube ?", "Un plan peut couper au maximum 6 faces. Pouvez-vous passer par le moyen de 6 bords ?", ["Hexagone régulier", "Pentagone régulier", "Octogone régulier", "Ellipses"], "Au moyen de 6 arêtes, vous obtenez un hexagone régulier. La symétrie du cube ne donne pas de pentagones, d'octogones (max. 6 côtés) ou de courbes."],
    "TSR5_14": ["Quel est le nombre maximum de côtés d’une section plane d’un cube ?", "Le polygone de section gagne un côté pour chaque face qui se croise.", ["6", "4", "8", "12"], "Le cube a 6 faces – au plus un hexagone (6 côtés)."],
    "TSR5_15": ["Le dodécaèdre régulier possède 12 faces pentagonales. Chaque face possède 5 arêtes, mais chaque arête est commune à 2 faces. Combien de bords a-t-il ?", "12 × 5 places de bord, chaque bord comptait deux fois.", ["30", "24", "36", "60"], "12 × 5 / 2 = 30 arêtes."],
    "TSR5_16": ["Dans un cube peint 7×7×7, découpé en 343 cubes, combien y a-t-il exactement de 2 faces peintes ?", "12(n − 2) avec n = 7.", ["60", "48", "72", "36"], "12 × 5 = 60."],
    "TSR5_17": ["Dans le cube 7×7×7, combien de petits cubes n’ont pas de face peinte ?", "(n − 2)³.", ["125", "64", "100", "27"], "5³ = 125."],
    "TSR5_18": ["Pour le cube peint n×n×n, le nombre de cubes avec exactement 1 face peinte est 6(n − 2)². Pourquoi y a-t-il 96 dans l’équation ?", "6(n − 2)² = 96 → (n − 2)² = 16.", ["6", "5", "7", "8"], "n − 2 = 4 → n = 6."],
    "TSR5_19": ["Quel est le nombre maximum de côtés d’une section traversant un prisme triangulaire ?", "Le prisme triangulaire possède 5 faces (2 triangles + 3 rectangles). Un plan peut-il supprimer les cinq ?", ["5", "4", "3", "6"], "Un plan incliné peut couper les deux bases et les 3 faces latérales — section pentagonale, maximum 5."],
    "TSR5_20": ["Dans le cube peint 7×7×7, combien de faces unitaires peintes les 343 cubes ont-ils au total ?", "Chacune des 6 faces du grand cube est une grille 7×7.", ["294", "252", "300", "343"], "6 × 49 = 294."],
    "TMP1_1": ["Un agriculteur possède 12 moutons. Tous meurent sauf cinq. Combien reste-t-il de moutons ?", "Concentrez-vous sur « tous sauf 5 ».", ["5", "7", "12", "0"], "\"Tous sauf 5 meurent\" signifie que 5 survivent. La réponse est 5 et non 12 moins 5."],
    "TMP1_2": ["Dans une course, vous dépassez la personne en 3ème place. Où es-tu en ce moment?", "Que se passe-t-il lorsque vous dépassez quelqu’un : prenez-vous sa place ?", ["Le 3ème", "Le 2ème", "Le 4ème", "Le 1er"], "Lorsque vous dépassez la personne en 3ème place, vous prenez sa place – vous devenez 3ème, pas 2ème."],
    "TMP1_3": ["Combien d’anniversaires une personne fête-t-elle en moyenne ?", "On n'est né qu'une fois.", ["1", "Environ 75", "365", "Cela dépend de l'âge"], "Tout le monde n’a qu’un seul anniversaire : le jour de sa naissance. Le reste sont des anniversaires de ce jour."],
    "TMP1_4": ["Si vous avez 5 oranges et que vous en prenez 2, combien en avez-vous ?", "Qui a pris les oranges ?", ["2", "3", "5", "0"], "Vous en avez pris 2 : vous en avez donc 2 sur vous. La question porte sur ce que vous possédez après les avoir prises, pas sur ce qui reste dans le panier."],
    "TMP1_5": ["A est le père de B, mais B n’est pas le fils de A. Comment est-ce possible ?", "Toutes les variantes de genre pour B.", ["B est la fille de A", "A n'est pas vraiment le père de B", "B est adopté", "Ce sont des beaux-parents"], "B est une fille – elle est la fille de A. Tous les enfants ne sont pas des garçons."],
    "TMP1_6": ["Combien de fois peut-on soustraire 10 de 100 ?", "Après le premier drop, en reste-t-il 100 ?", ["1", "10", "9", "De l'infini"], "Une seule fois – après cela, vous avez 90 et soustrayez 10 de 90, pas 100."],
    "TMP1_7": ["Si un coq pond un œuf sur le toit, dans quel sens l’œuf roule-t-il ?", "Qu'est-ce qu'un coq, exactement ?", ["Les coqs ne pondent pas d'œufs", "À gauche", "À droite", "Il reste en haut"], "Un coq est un mâle et ne pond pas d’œufs. La prémisse est impossible."],
    "TMP1_8": ["Qu'est-ce qui pèse le plus : une livre de plumes ou une livre de briques ?", "Regardez attentivement l'unité de mesure.", ["De même", "Les briques", "Plumes", "Ça dépend"], "Une livre est une livre, quel que soit le matériau. Les deux pèsent exactement une livre."],
    "TMP1_9": ["Une chemise coûtait 50 $ et c'est 50 % de réduction. Combien payez-vous ?", "Calcule 50 % du prix initial.", ["25 $", "50 $", "30 $", "15 $"], "50% de 50$ = 25$."],
    "TMP1_10": ["Vous êtes dans une pièce sombre avec une bougie, une lampe à huile et une cheminée. Vous n'avez qu'un seul match. Qu'allumez-vous la première fois ?", "Il faut allumer quelque chose avant toute autre chose.", ["Le match", "La bougie", "La lampe", "La cheminée"], "Vous devez d’abord allumer l’allumette pour pouvoir allumer le reste."],
    "TMP1_11": ["Un avion s'écrase à la frontière de deux pays. Où enterrer les survivants ?", "Lisez attentivement : qui enterrons-nous ?", ["N'enterrez pas les survivants", "Dans le pays de départ", "Dans le pays de destination", "A la frontière"], "Les survivants sont vivants : ne les enterrez pas."],
    "TMP1_12": ["Combien d’animaux de chaque espèce Moïse a-t-il emmenés dans l’arche ?", "Vérifiez le nom dans la question.", ["Aucun : c'était Noé, pas Moïse", "2", "7", "1"], "Moïse n'avait pas d'arche, mais Noé en avait. La question utilise un mauvais nom pour vous induire en erreur."],
    "TMP1_13": ["Il y a 10 oiseaux sur une clôture. Tirez-en un. Combien en reste-t-il sur la barrière ?", "Comment les autres réagissent-ils à la fusillade ?", ["0", "9", "10", "1"], "Le bruit les effraie tous. Il n’en reste plus."],
    "TMP1_14": ["Un agriculteur possède 20 vaches. Tous meurent sauf 12. Combien en reste-t-il ?", "\"Tous sauf 12\".", ["12", "8", "20", "0"], "Douze survivent."],
    "TMP1_15": ["Qu'est-ce qui monte toujours et ne descend jamais ?", "Quelque chose qui ne fait que grandir avec le temps.", ["Votre âge", "Un ballon", "Le soleil", "La température"], "L'âge ne fait qu'augmenter."],
    "TMP1_16": ["Une fille frappe la balle à 3 m. Cela lui revient sans mur, sans autre personne, sans spin. Comment?", "De quelle manière l'a-t-il frappée ?", ["Il l'a frappée verticalement vers le haut", "Le vent", "Il a sauté de l'arbre", "La pente"], "Il lui a donné un coup de pied ; la gravité l'a ramené."],
    "TMP1_17": ["Qu'est-ce qui a une tête et une queue mais pas de corps ?", "Des objets ordinaires, pas des animaux.", ["Une pièce de monnaie", "Un serpent", "Une aiguille", "Une comète"], "La pièce a une face (tête) et une queue (queue), pas de corps."],
    "TMP1_18": ["Le médecin vous donne 5 comprimés : un toutes les heures. Combien de temps dure le traitement ?", "Quand prends-tu ta première pilule ?", ["4 heures", "5 heures", "6 heures", "3 heures"], "Heure 0, 1, 2, 3, 4 — les 4 dernières heures entre une et cinq heures. Total 4 heures depuis le début."],
    "TMP1_19": ["Vous avez un bol avec 6 œufs et vous en sortez 2. Combien en avez-vous ?", "Où sont les œufs que vous avez pris ?", ["2", "4", "6", "0"], "Vous en avez pris 2 : vous en avez donc 2 sur vous. Il en reste 4 dans le bol, mais la question porte sur ce que vous possédez."],
    "TMP1_20": ["Un garçon a 4 ans, sa sœur a la moitié de son âge. Quand le garçon a 100 ans, quel âge a la sœur ?", "La différence d'âge reste la même.", ["98", "50", "100", "96"], "La sœur a 2 ans de moins (4÷2=2). 100 − 2 = 98."],
    "TMP2_1": ["Un stylo et un cahier coûtent ensemble 1,10 $. Le cahier coûte 1,00 $ de plus que le stylo. Combien coûte le stylo ?", "Soit x le prix du stylo ; le carnet coûte x + 1,00 $.", ["0,05 $", "0,10 $", "1,00 $", "0,50 $"], "x + (x + 1) = 1,10 → 2x = 0,10 → x = 0,05 $."],
    "TMP2_2": ["Le médecin vous donne 3 comprimés : un toutes les 45 minutes. Combien de temps cela prend-il?", "Quand prends-tu ta première pilule ?", ["90 minutes", "135 minutes", "45 minutes", "120 minutes"], "À 0, 45 et 90 minutes, un total de 90 minutes s'écoule."],
    "TMP2_3": ["5 ouvriers construisent 5 murs en 5 jours. Combien de temps faut-il à 10 ouvriers pour construire 10 murs ?", "Combien faut-il à un ouvrier pour construire un mur ?", ["5 jours", "10 jours", "2,5 jours", "1 jour"], "Chacun construit 1 mur en 5 jours. 10 personnes, 10 murs parallèles — également 5 jours."],
    "TMP2_4": ["Deux pièces font 30 centimes. L'un n'est pas un nickel (5 ¢). Quelles sont les monnaies ?", "\"L'un n'est pas une pièce de cinq cents\" — qu'est-ce que l'autre ?", ["25 ¢ et 5 ¢ (quart + nickel)", "Deux pièces de 10 ¢", "50 ¢", "10 ¢ et 5 ¢"], "L'un est un quart (25 ¢), pas un nickel; l'autre est du nickel (5 ¢). Total 30 ¢."],
    "TMP2_5": ["Multipliez tous les chiffres d'un clavier téléphonique (0 à 9). Quel est le produit ?", "Que se passe-t-il lorsque vous multipliez par un certain nombre ?", ["0", "3 628 800", "362 880", "45"], "Parmi les nombres se trouve 0. Tout produit qui inclut 0 est 0."],
    "TMP2_6": ["Une famille compte 4 garçons et 3 filles. Chaque garçon a autant de sœurs que de frères. Chaque fille a deux fois plus de frères que de sœurs. Combien y a-t-il d'enfants ?", "Comptez du point de vue de chaque enfant.", ["7", "8", "6", "10"], "Garçon : 3 frères, 3 sœurs ✓. Fille : 4 frères, 2 sœurs (4 = 2×2) ✓. Total 7."],
    "TMP2_7": ["Un train électrique se dirige vers le nord. Le vent souffle de l'ouest. Où va la fumée ?", "Quel type de propulsion le train possède-t-il ?", ["Il n'y a pas de fumée", "Ouest", "Nord", "Est"], "Le train électrique ne brûle pas de carburant, il ne produit pas de fumée."],
    "TMP2_8": ["8 personnes construisent un mur en 10 heures. Combien de temps cela prend-il à 4 personnes ?", "La moitié des gens doublent leur temps.", ["20 heures", "5 heures", "40 heures", "10 heures"], "10 × 2 = 20 heures."],
    "TMP2_9": ["Combien de mois dans l’année comptent (au moins) 30 jours ?", "Certains mois comportent plus de 30 jours.", ["11", "4", "6", "7"], "Tous les mois ont au moins 30 jours sauf février. Donc 11 mois."],
    "TMP2_10": ["Creusez 6 trous : 3 grands et 3 petits. combien de trous as-tu", "La taille change-t-elle le fait que ce soit un trou ?", ["6", "3", "9", "0"], "Les 6 trous."],
    "TMP2_11": ["Pouvez-vous citer trois jours consécutifs sans lundi, mardi, mercredi, jeudi, vendredi, samedi, dimanche ?", "Des termes relatifs, pas des noms propres.", ["Hier, aujourd'hui et demain", "Jour 1, 2, 3", "Impossible", "Matin, midi, soir"], "Hier, aujourd'hui, demain sont toujours trois jours consécutifs."],
    "TMP2_12": ["Combien font 1/2 de 2/3 de 3/4 de 4/5 de 100 ?", "Simplifiez les fractions avant la multiplication.", ["20", "10", "50", "25"], "1/2 × 2/3 × 3/4 × 4/5 = 1/5. 1/5 × 100 = 20."],
    "TMP2_13": ["Un nénuphar double sa surface chaque jour. Au jour 20, remplissez le lac. Quel jour a-t-il couvert exactement 25 % ?", "Reculez : divisez par 2 chaque jour.", ["Jour 18", "Jour 5", "Jour 15", "Jour 10"], "Jour 20 : 100 %. Jour 19 : 50%. Jour 18 : 25%."],
    "TMP2_14": ["Une brique pèse 1 kg plus la moitié de son poids. Combien ça pèse ?", "Soit b le poids : b = 1 + b/2.", ["2kg", "1,5kg", "3kg", "1 kg"], "b/2 = 1 → b = 2 kg."],
    "TMP2_15": ["6 hommes creusent 6 trous en 6 heures. Combien de temps faut-il à 3 personnes pour creuser 3 trous ?", "Combien de temps faut-il à une personne pour creuser un trou ?", ["6 heures", "3 heures", "12 heures", "9 heures"], "Chacun creuse 1 trou en 6 heures. 3 personnes, 3 trous en parallèle — également 6 heures."],
    "TMP2_16": ["Quelle est la lettre suivante : O, T, T, F, F, S, S, ?", "En anglais : les initiales des nombres One, Two, Three…", ["E", "N", "T", "H"], "Un, Deux, Trois, Quatre, Cinq, Six, Sept, Huit → O, T, T, F, F, S, S, E."],
    "TMP2_17": ["Vous disposez de 8 balles : 7 identiques, une plus lourde. Avec une balance, combien de pesées minimum pour la retrouver ?", "Divisez-vous en trois groupes, pas deux.", ["2", "3", "1", "4"], "3 contre 3 ; puis 1 contre 1 ou du groupe dur. Maximum 2 pesées."],
    "TMP2_18": ["Dans une course, vous dépassez le dernier. Sur quel siège es-tu ?", "Qui se cache derrière le dernier ?", ["C'est impossible", "Le dernier", "L'avant-dernier", "Le premier"], "Il n'y a personne derrière le dernier, vous ne pouvez pas être derrière pour le battre."],
    "TMP2_19": ["3 chats attrapent 3 souris en 3 minutes. Combien de temps faut-il à 100 chats pour attraper 100 souris ?", "Combien de minutes un chat attrape-t-il une souris ?", ["3 minutes", "100 minutes", "33 minutes", "1 minute"], "Chacun attrape 1 souris en 3 minutes. En parallèle — aussi 3 minutes."],
    "TMP2_20": ["Quelle fraction d'une journée représente 6 heures ?", "Combien d'heures y a-t-il dans la journée ?", ["1/4", "1/6", "1/3", "1/2"], "6/24 = 1/4."],
    "TMP3_1": ["6 machines fabriquent 6 jouets en 6 minutes. Combien de temps faut-il à 12 machines pour fabriquer 12 jouets ?", "Combien de minutes une machine fabrique-t-elle un jouet ?", ["6 minutes", "12 minutes", "3 minutes", "1 minute"], "Chacun fabrique 1 jouet en 6 minutes. 12 voitures en parallèle — également 6 minutes."],
    "TMP3_2": ["L'horloge indique 6h00. Quel est l'angle entre l'aiguille des heures et l'aiguille des minutes ?", "Où pointent les langues à 6 heures précises ?", ["180°", "90°", "120°", "360°"], "Aiguille des minutes à 12h, aiguille des heures à 6h — ligne droite, 180°."],
    "TMP3_3": ["L'horloge indique 9h00. Quel est l'angle entre les langues ?", "Où regardent les langues à 9 heures précises ?", ["90°", "180°", "270°", "45°"], "Aiguille des minutes à 12h, aiguille des heures à 9h – angle droit, 90°."],
    "TMP3_4": ["Dans une grille, colonne 1 + colonne 2 = colonne 3. Lignes : [3, 5, 8], [7, 2, 9], [4, 6, ?]. Trouvez le numéro manquant.", "Appliquez la même règle à la troisième rangée.", ["10", "8", "12", "6"], "4 + 6 = 10."],
    "TMP3_5": ["Dans une grille, colonne 1 × colonne 2 = colonne 3. Lignes : [2, 5, 10], [3, 4, 12], [6, 3, ?]. Trouvez le numéro manquant.", "Multipliez les deux premières colonnes de la troisième ligne.", ["18", "9", "15", "21"], "6 × 3 = 18."],
    "TMP3_6": ["Un escargot grimpe de 4 m le jour et glisse de 2 m la nuit. Le mur fait 12 m. Combien de jours faut-il pour atteindre le sommet ?", "Le dernier jour, il peut sortir avant de repartir.", ["5 jours", "6 jours", "4 jours", "10 jours"], "Filet +2 m par cycle. Après 4 jours : 8 m. Le 5ème jour, montée 8+4=12 m — arrivée avant la nuit."],
    "TMP3_7": ["2 personnes peignent 2 pièces en 2 heures. Combien de temps cela prend-il avec 4 personnes et 4 chambres ?", "Combien d'heures un homme peint-il une pièce ?", ["2 heures", "4 heures", "1 heure", "8 heures"], "Chacun peint 1 pièce en 2 heures. 4 personnes, 4 pièces en parallèle — 2 heures également."],
    "TMP3_8": ["Vous achetez quelque chose pour 3 $ et vous le vendez pour 5 $. Ensuite, vous achetez autre chose pour 6 $ et vous le vendez pour 9 $. Quel est le bénéfice total ?", "Le bénéfice de chaque transaction séparément.", ["5 $", "3 $", "2 $", "6 $"], "5−3=2, 9−6=3. Total 5 $."],
    "TMP3_9": ["Une grenouille saute de 3 m en avant et glisse de 1 m en arrière par cycle. Combien de sauts jusqu'à dépasser les 10 m ?", "Le dernier saut peut se faire sans rechute.", ["5 sauts", "4 sauts", "6 sauts", "10 sauts"], "Après 4 cycles : 8 m. 5ème saut : 8+3=11 m > 10. Donc 5."],
    "TMP3_10": ["Tom a 3 fois l'âge de Jim. Dans 10 ans, Tom aura deux fois l'âge de Jim. Quel âge a Jim maintenant ?", "T = 3J ; T+10 = 2(J+10).", ["10", "5", "15", "20"], "3J+10 = 2J+20 → J = 10."],
    "TMP3_11": ["Vous achetez un cheval pour 60 $, le vendez pour 70 $, le rachetez pour 80 $ et le revendez pour 90 $. Bénéfice total ?", "Chaque transaction séparément.", ["20 $", "10 $", "30 $", "0 $"], "+10$ puis +10$ = 20$."],
    "TMP3_12": ["Vous pliez une feuille en deux 7 fois. Combien de couches ?", "Chaque pli double les couches.", ["128", "64", "14", "256"], "2⁷ = 128."],
    "TMP3_13": ["Un nombre premier multiplié par lui-même donne 169. Quel est ce nombre ?", "La racine carrée de 169.", ["13", "11", "17", "7"], "√169 = 13, qui est premier."],
    "TMP3_14": ["Deux trains sont distants de 100 milles l'un de l'autre, chacun se dirigeant à 50 mph l'un vers l'autre. Une mouche vole à 75 mph entre eux. Dans combien de temps les trains se croisent-ils ?", "Dans combien de temps se rencontreront-ils ?", ["75 milles", "100 milles", "50 milles", "150 milles"], "Vitesse relative 100 mph → 1 heure. Voler : 75 × 1 = 75 milles."],
    "TMP3_15": ["Quel est le plus petit nombre divisible par 1, 2, 3, 4, 5 et 6 ?", "Le plus petit commun multiple (CMMMC).", ["60", "30", "120", "720"], "CMMMC(1…6) = 60."],
    "TMP3_16": ["En comptant de 1 à 100, combien de fois le chiffre 7 apparaît-il ?", "Unités et dizaines séparément.", ["20", "10", "11", "19"], "Unités : 7,17,…,97 — 10. Dizaines : 70–79 — 10. Total 20."],
    "TMP3_17": ["Un nombre augmente de 20 % et devient 60. De quoi s'agissait-il à l'origine ?", "1,2x = 60.", ["50", "48", "72", "40"], "x = 60 / 1,2 = 50."],
    "TMP3_18": ["Vous pliez une feuille en deux 10 fois. Combien de couches ?", "Chaque pli double.", ["1024", "100", "512", "2048"], "2¹⁰ = 1024."],
    "TMP3_19": ["Le produit de deux entiers positifs consécutifs est 156. De quoi s’agit-il ?", "Deux nombres consécutifs dont le produit est 156.", ["12 et 13", "11 et 12", "13 et 14", "10 et 15"], "12 × 13 = 156."],
    "TMP3_20": ["Carré magique 3×3 : chaque ligne, colonne et diagonale totalisent 15. Première rangée [2, 7, 6], milieu [9, 5, 1]. Quel est le premier chiffre de la dernière ligne ?", "La première colonne totalise également 15.", ["4", "3", "6", "8"], "2 + 9 + ? = 15 → ? = 4."],
    "TMP4_1": ["Une colonie de bactéries double toutes les heures et remplit complètement un pot à midi. A quelle heure était le pot à un quart ?", "Reculez : divisez par 2 toutes les heures.", ["10h00", "11h00", "9h00", "6h00"], "Midi : 100%. 11h00 : 50%. 10h00 : 25%."],
    "TMP4_2": ["Vous disposez de 24 pièces ; l'une est fausse et plus légère. Combien de pesées minimum sur une balance pour la retrouver avec certitude ?", "Divisez-vous en trois groupes à chaque étape.", ["3", "4", "5", "2"], "8 contre 8, puis dans le groupe léger 3 contre 3, puis 1 contre 1 — 3 pesées."],
    "TMP4_3": ["Une corde est coupée en 3 morceaux. Chaque morceau est coupé en 3 plus petits. Combien de pièces au total ?", "3 × 3.", ["9", "6", "12", "27"], "3 × 3 = 9."],
    "TMP4_4": ["Un ver se trouve au fond d'un puits de 30 m. Il grimpe de 5 m le jour et glisse de 4 m la nuit. Combien de jours sort-il?", "Le dernier jour, il ressort sans reculer.", ["26 jours", "30 jours", "25 jours", "27 jours"], "Net +1 m/jour. Après 25 jours : 25 m. Jour 26 : 25+5=30 m."],
    "TMP4_5": ["8 hommes construisent un mur en 10 jours. Combien de jours avec 5 hommes ?", "Travail total = personnes × jours.", ["16 jours", "12 jours", "20 jours", "8 jours"], "8×10 = 80 jours-homme. 80/5 = 16 jours."],
    "TMP4_6": ["Les tuyaux A et B remplissent un réservoir en 6 h et 3 h respectivement. Combien de temps restent-ils tous les deux ouverts ?", "Ajoute les débits : 1/6 + 1/3 par heure.", ["2 heures", "4,5 heures", "3 heures", "1,5 heures"], "1/6+2/6=1/2 par heure → 2 heures."],
    "TMP4_7": ["Un rectangle est 3 fois plus long que large. Le périmètre est de 48 m. Quelle est la superficie ?", "l = 3w; 2(s+3s)=48.", ["108 m²", "96 m²", "144 m²", "48 m²"], "8w=48 → w=6, longueur 18 m, aire 108 m²."],
    "TMP4_8": ["Un nombre augmente de 20 %, puis diminue de 20 %. Quel est le changement net par rapport à l'original ?", "Appliquez les pourcentages un à la fois.", ["4% de diminution", "0%", "Augmentation de 4 %", "2% de réduction"], "100 → 120 → 96. -4% net."],
    "TMP4_9": ["Le magasin augmente les prix de 25 %, puis réduit de 20 %. Le changement net ?", "1,25 × 0,80.", ["0 % (aucun changement)", "+5%", "-5%", "+45%"], "1,25 × 0,80 = 1 — en place."],
    "TMP4_10": ["La somme des 20 premiers nombres naturels positifs ?", "n(n+1)/2.", ["210", "200", "190", "220"], "20×21/2 = 210."],
    "TMP4_11": ["L'angle entre les aiguilles de l'horloge à 4h30 ?", "L'horaire est entre quatre heures et cinq heures et demie.", ["45°", "90°", "60°", "30°"], "Minute 180°, horaire 135°, différence 45°."],
    "TMP4_12": ["La voiture parcourt 60 km à 30 km/h, puis 60 km à 60 km/h. Vitesse moyenne ?", "Distance totale / temps total.", ["40km/h", "45km/h", "50km/h", "35km/h"], "2h + 1h = 3h ; 120/3 = 40 km/h."],
    "TMP4_13": ["Si 2¹⁰ = 1024, que vaut 2¹² ?", "2¹⁰ × 2².", ["4096", "2048", "8192", "1248"], "1024 × 4 = 4096."],
    "TMP4_14": ["Un robinet remplit la piscine en 4 h ; le drain le nettoie en 8 h. combien de temps faut-il pour remplir les deux ouverts ?", "Débit net = remplissage − vidange.", ["8 heures", "6 heures", "12 heures", "4 heures"], "1/4 − 1/8 = 1/8 par heure → 8 heures."],
    "TMP4_15": ["Le prix baisse de 10 %, puis encore de 10 %. La baisse totale par rapport à l'original ?", "Les seconds 10 % sont sur le prix déjà réduit.", ["19%", "20%", "18%", "21%"], "0,9 × 0,9 = 0,81 → diminution de 19 %."],
    "TMP4_16": ["Trouvez x : 3x + 7 = 22.", "Isoler x.", ["5", "7", "3", "10"], "3x=15 → x=5."],
    "TMP4_17": ["Un train de 100 m roule à 50 m/s. Combien de temps leur faut-il pour dépasser complètement un poteau ?", "La longueur du train doit être couverte.", ["2 secondes", "1 seconde", "4 secondes", "0,5 seconde"], "100/50 = 2 s."],
    "TMP4_18": ["Deux ouvriers terminent un travail en 12 jours. Un en 20 jours. Combien faut-il à l'autre seul ?", "1/12 - 1/20.", ["30 jours", "24 jours", "15 jours", "40 jours"], "1/30 par jour → 30 jours."],
    "TMP4_19": ["Vous investissez 1 000 $ à 5 % d’intérêt simple par an, pendant 3 ans. Quel est le montant total des intérêts ?", "Intérêt simple = capital × taux × temps.", ["150 $", "1 150 $", "50 $", "300 $"], "1 000 × 0,05 × 3 = 150 $."],
    "TMP4_20": ["Le fermier possède des poules et des vaches. 20 têtes et 56 pieds. combien de poulets", "g + v = 20 ; 2g + 4v = 56.", ["12", "8", "14", "10"], "v=8, g=12."],
    "TMP5_1": ["Vous avez deux cordes ; chacun brûle complètement en 1 heure exactement, mais de manière irrégulière. Comment mesure-t-on exactement 45 minutes ?", "Que se passe-t-il si vous allumez une corde aux deux extrémités ?", ["Vous allumez la corde 1 aux deux extrémités et la corde 2 à une extrémité, simultanément", "Vous allumez les deux cordes à une extrémité", "Coupez une corde en quatre et allumez un morceau", "Tu allumes une corde, tu attends qu'elle brûle, puis l'autre"], "La corde 1 (les deux extrémités) brûle en 30 min. Allumez ensuite l’autre extrémité de la corde 2 – encore 15 minutes. Totale : 45 minutes."],
    "TMP5_2": ["Deux pères et deux fils mangent. Mangez exactement 3 œufs, un chacun. Comment est-ce possible ?", "Une personne peut-elle jouer deux rôles ?", ["Grand-père, père et fils (3 personnes)", "On n'a pas mangé", "Il y en avait 4, mais les œufs étaient partagés", "Quelqu'un a mangé deux œufs"], "Trois générations : grand-père (père), père (et fils et père), fils. Deux pères + deux fils = 3 personnes."],
    "TMP5_3": ["100 casiers en enfilade, tous verrouillés. L'élève k change chaque kième casier. Combien restent-ils ouverts à la fin ?", "Une armoire est ouverte si elle est commutée un nombre impair de fois. Quels nombres ont un nombre impair de diviseurs ?", ["10", "50", "25", "0"], "Carrés parfaits uniquement : 1, 4, 9, 16, 25, 36, 49, 64, 81, 100 — 10 armoires."],
    "TMP5_4": ["Trois interrupteurs à l’extérieur d’une pièce fermée contrôlent trois ampoules à l’intérieur. Vous ne pouvez entrer qu’une seule fois. Comment identifier chaque interrupteur ?", "Une ampoule restée allumée longtemps reste chaude même après extinction.", ["Allumez 1, attendez, éteignez ; allumez 2 ; entrez : chaude éteinte = 1, allumée = 2, froide éteinte = 3", "Actionnez-les un par un et entrez après chaque action", "Allumez puis éteignez rapidement les trois, puis entrez", "Regardez par le trou de la serrure après chaque changement"], "Méthode correcte : 1 allumé quelques minutes, puis éteint ; 2 allumé ; 3 éteint. En entrant : chaude éteinte = 1, allumée = 2, froide éteinte = 3."],
    "TMP5_5": ["Trois cartons étiquetés « Pommes », « Oranges », « Mélange ». Toutes les étiquettes sont fausses. Vous prélevez un fruit d’une boîte. Laquelle ouvrir ?", "La boîte « Mélange » n’est pas un mélange si l’étiquette est fausse.", ["Boîte « Mélange »", "Boîte « Pommes »", "Boîte « Oranges »", "N’importe quelle boîte"], "Ouvrez « Mélange » : le contenu est homogène (pommes ou oranges). Selon le fruit tiré, on en déduit tout le classement réel."],
    "TMP5_6": ["Un homme a trois filles. Le produit des âges est 36. La somme est le numéro de la maison voisine (ambigu). L'aîné joue du piano. Quels sont les âges ?", "Deux triplets de diviseurs de 36 ont la même somme. \"Le plus gros\" élimine un cas.", ["2, 2 et 9", "1, 6 et 6", "3, 3 et 4", "1, 4 et 9"], "Sommes 13 : {1,6,6} et {2,2,9}. Il existe un «plus grand» unique → {2, 2, 9}."],
    "TMP5_7": ["Le problème de Monty Hall : vous choisissez la porte 1 sur 3 (une voiture, deux chèvres). L'hôte ouvre la porte 3 - chèvre. Est-ce que tu te changes à la porte 2 ?", "Quelle était la probabilité initiale pour votre porte ?", ["Oui – le changement gagne 2/3 du temps", "Non, c'est 50/50", "Ce n'est pas grave", "Non, le premier choix est généralement le bon"], "Votre choix : 1/3. La porte restante est 2/3. Le changement double les chances."],
    "TMP5_8": ["Combien de carrés de n’importe quelle taille sur un échiquier 8×8 ?", "Comptez séparément 1×1, 2×2,… 8×8.", ["204", "64", "256", "100"], "8²+7²+…+1² = 204."],
    "TMP5_9": ["La somme des nombres de 1 à 100 ?", "Formule de Gauss : n(n+1)/2.", ["5050", "5000", "10000", "10100"], "100×101/2 = 5050."],
    "TMP5_10": ["Combien de zéros à la fin de 100 !?", "Les zéros proviennent des facteurs 10 = 2×5. Comptez les puissances de 5.", ["24", "20", "25", "10"], "⌊100/5⌋ + ⌊100/25⌋ = 24."],
    "TMP5_11": ["Le paysan traverse la rivière avec le loup, la chèvre et le chou. Bateau : fermier + un objet. Le loup mange la chèvre laissée seule ; la chèvre mange le chou. Par quoi ça commence ?", "Quel couple peut-on laisser seul sur le rivage ?", ["Chèvre", "Le loup", "Chou", "Ce n'est pas grave"], "D'abord la chèvre. Le loup et le chou sont en sécurité. Puis le reste à tour de rôle."],
    "TMP5_12": ["Partant d'un couple de lapins, ils arrivent à maturité en 1 mois et produisent un nouveau couple tous les mois après maturité. Combien de paires après 6 mois ?", "Suite de Fibonacci : 1, 1, 2, 3, 5, 8, …", ["8", "13", "6", "10"], "Mois 1 à 6 : 1, 1, 2, 3, 5, 8 paires."],
    "TMP5_13": ["Nombre minimum de coups dans les Tours de Hanoï avec 5 disques ?", "2ⁿ − 1, n = nombre de disques.", ["31", "32", "63", "15"], "2⁵ − 1 = 31."],
    "TMP5_14": ["Nombre minimum de personnes dans une pièce tel qu'il y a > 50 % de probabilité que deux aient le même anniversaire ?", "Le paradoxe de l’anniversaire : la réponse est loin d’être ce que l’on voit.", ["23", "50", "183", "365"], "Chez 23 personnes, la probabilité dépasse 50 %."],
    "TMP5_15": ["Dans une pièce de 23 personnes, quelle est la probabilité approximative qu’au moins deux aient le même anniversaire ?", "Le résultat du paradoxe de l'anniversaire.", ["environ 50%", "environ 6%", "environ 25%", "environ 75%"], "Avec 23 personnes, ~50,7%."],
    "TMP5_16": ["Sur une île, les chevaliers disent la vérité, les escrocs mentent. Dire : \"Nous sommes tous les deux des escrocs\". Qu’est-ce que A ?", "Si A était un chevalier, cette affirmation pourrait-elle être vraie ?", ["Escroc", "Chevalier", "On ne peut pas déterminer", "Aucun"], "Un chevalier ne pouvait pas dire « les deux escrocs ». Donc A ment ; l'affirmation est fausse : ils ne sont pas tous les deux des escrocs, l'autre est un chevalier."],
    "TMP5_17": ["La somme des angles intérieurs d'un heptagone (7 côtés) ?", "(n − 2) × 180°.", ["900°", "720°", "1080°", "1260°"], "5 × 180° = 900°."],
    "TMP5_18": ["Combien de carrés de n’importe quelle taille dans une grille 4×4 ?", "1×1, 2×2, 3×3, 4×4.", ["30", "16", "20", "25"], "4²+3²+2²+1² = 30."],
    "TMP5_19": ["Vous lancez une pièce équitable 3 fois. La probabilité d'apparaître au moins une fois « tête » ?", "Le complément : jamais tête (trois fois page).", ["7/8", "3/4", "1/2", "1/8"], "P(pas de tête) = (1/2)³ = 1/8. P(au moins une tête) = 7/8."],
    "TMP5_20": ["Combien de rectangles dans les lignes d'une grille 3×3 (4 horizontales, 4 verticales) ?", "Vous en choisissez 2 horizontaux et 2 verticaux.", ["36", "18", "24", "9"], "C(4,2)² = 36."],
  }
});
